// TinyURL лӢЁм¶• URL мғқм„ұ н•ЁмҲҳ
async function shortenUrl(longUrl) {
  try {
    const response = await axios.get(`https://tinyurl.com/api-create.php?url=${encodeURIComponent(longUrl)}`);
    console.log(`рҹ”— URL лӢЁм¶• м„ұкіө: ${response.data}`);
    return response.data;
  } catch (error) {
    console.error(`рҹ”— URL лӢЁм¶• мӢӨнҢЁ: ${error.message}`);
    return longUrl; // мӢӨнҢЁ мӢң мӣҗліё URL л°ҳнҷҳ
  }
}

// мЈјк°„ мӢңмһ‘мқј кі„мӮ° н•ЁмҲҳ (мӣ”мҡ”мқј кё°мӨҖ)
function getWeekStart() {
  const now = new Date();
  const day = now.getDay();
  const diff = now.getDate() - day + (day === 0 ? -6 : 1); // мӣ”мҡ”мқјлЎң мЎ°м •
  const monday = new Date(now.setDate(diff));
  return monday.toISOString().split('T')[0]; // YYYY-MM-DD нҳ•мӢқ
}

// л°”мқҙнҠё кі„мӮ° н•ЁмҲҳ (н•ңкёҖ 2л°”мқҙнҠё, к·ё мҷё 1л°”мқҙнҠё)
function getByteLength(str) {
  let byteLen = 0;
  for (let i = 0; i < str.length; i++) {
    byteLen += str.charCodeAt(i) > 127 ? 2 : 1;
  }
  return byteLen;
}

// мқҙлӘЁм§Җ м ңкұ° н•ЁмҲҳ (SMS нҳёнҷҳмҡ©)
function removeEmoji(str) {
  return str.replace(/[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F1E0}-\u{1F1FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{231A}-\u{231B}]|[\u{23E9}-\u{23F3}]|[\u{23F8}-\u{23FA}]|[\u{25AA}-\u{25AB}]|[\u{25B6}]|[\u{25C0}]|[\u{25FB}-\u{25FE}]|[\u{2614}-\u{2615}]|[\u{2648}-\u{2653}]|[\u{267F}]|[\u{2693}]|[\u{26A1}]|[\u{26AA}-\u{26AB}]|[\u{26BD}-\u{26BE}]|[\u{26C4}-\u{26C5}]|[\u{26CE}]|[\u{26D4}]|[\u{26EA}]|[\u{26F2}-\u{26F3}]|[\u{26F5}]|[\u{26FA}]|[\u{26FD}]|[\u{2702}]|[\u{2705}]|[\u{2708}-\u{270D}]|[\u{270F}]|[\u{2712}]|[\u{2714}]|[\u{2716}]|[\u{271D}]|[\u{2721}]|[\u{2728}]|[\u{2733}-\u{2734}]|[\u{2744}]|[\u{2747}]|[\u{274C}]|[\u{274E}]|[\u{2753}-\u{2755}]|[\u{2757}]|[\u{2763}-\u{2764}]|[\u{2795}-\u{2797}]|[\u{27A1}]|[\u{27B0}]|[\u{27BF}]|[\u{2934}-\u{2935}]|[\u{2B05}-\u{2B07}]|[\u{2B1B}-\u{2B1C}]|[\u{2B50}]|[\u{2B55}]|[\u{3030}]|[\u{303D}]|[\u{3297}]|[\u{3299}]/gu, '').trim();
}

// SMS л°ңмҶЎ н•ЁмҲҳ (Aligo)
async function sendSMS(to, text) {
  try {
    // м „нҷ”лІҲнҳё м •лҰ¬ (н•ҳмқҙн”Ҳ м ңкұ°)
    const cleanTo = to.replace(/-/g, '');

    // мқҙлӘЁм§Җ м ңкұ°
    const cleanText = removeEmoji(text);

    // Aligo APIлҠ” form-urlencoded нҳ•мӢқ мӮ¬мҡ©
    const params = new URLSearchParams();
    params.append('key', ALIGO_API_KEY);
    params.append('user_id', ALIGO_USER_ID);
    params.append('sender', SMS_SENDER);
    params.append('receiver', cleanTo);
    params.append('msg', cleanText);
    // 90л°”мқҙнҠё мҙҲкіј мӢң LMSлЎң м „нҷҳ
    const byteLen = getByteLength(text);
    if (byteLen > 90) {
      params.append('msg_type', 'LMS');
    } else {
      params.append('msg_type', 'SMS');
    }

    const response = await axios.post('https://apis.aligo.in/send/', params, {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    // Aligo мқ‘лӢө: result_codeк°Җ 1мқҙл©ҙ м„ұкіө
    if (response.data.result_code === '1' || response.data.result_code === 1) {
      console.log(`рҹ“ұ SMS л°ңмҶЎ м„ұкіө (Aligo): ${cleanTo}, msg_id: ${response.data.msg_id}`);
      return { success: true, result: response.data };
    } else {
      console.error(`рҹ“ұ SMS л°ңмҶЎ мӢӨнҢЁ (Aligo): ${JSON.stringify(response.data)}`);
      return { success: false, error: response.data };
    }
  } catch (error) {
    const errorData = error.response?.data ? JSON.stringify(error.response.data) : error.message;
    console.error(`рҹ“ұ SMS л°ңмҶЎ мҳӨлҘҳ (Aligo): ${errorData}`);
    return { success: false, error: error.response?.data || error.message };
  }
}

// лӢЁмӣҗлӘ… м¶•м•Ҫ н•ЁмҲҳ (90л°”мқҙнҠё л§һм¶”кё°)
function truncateUnitTitle(title, maxBytes) {
  let result = '';
  let byteLen = 0;
  for (let i = 0; i < title.length; i++) {
    const charBytes = title.charCodeAt(i) > 127 ? 2 : 1;
    if (byteLen + charBytes > maxBytes) {
      return result + '...';
    }
    result += title[i];
    byteLen += charBytes;
  }
  return result;
}

// н•ҷл¶ҖлӘЁ м•ҢлҰј л°ңмҶЎ н•ЁмҲҳ (90л°”мқҙнҠё мқҙлӮҙ SMS мң м§Җ)
async function sendParentNotification(studentName, parentPhone, type, additionalInfo = {}) {
  if (!parentPhone) {
    console.log(`рҹ“ұ н•ҷл¶ҖлӘЁ м—°лқҪмІҳ м—ҶмқҢ: ${studentName}`);
    return { success: false, error: 'н•ҷл¶ҖлӘЁ м—°лқҪмІҳ м—ҶмқҢ' };
  }

  let message = '';
  // н•ңкөӯ мӢңк°„(KST, UTC+9)мңјлЎң ліҖнҷҳ
  const now = new Date();
  const kstOptions = { timeZone: 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hour12: false };
  const timeStr = now.toLocaleTimeString('ko-KR', kstOptions);

  switch (type) {
    case 'login':
      // [лёҢл Ҳмқёл¬ён•ҙмӣҗ] нҷҚкёёлҸҷ н•ҷмғқмқҙ 16:47м—җ н•ҷмҠө мӢңмһ‘н–Ҳм–ҙмҡ”!
      // н•Ёк»ҳ мқ‘мӣҗн•ҙ мЈјм„ёмҡ”!
      message = `[лёҢл Ҳмқёл¬ён•ҙмӣҗ] ${studentName} н•ҷмғқмқҙ ${timeStr}м—җ н•ҷмҠө мӢңмһ‘н–Ҳм–ҙмҡ”!\nн•Ёк»ҳ мқ‘мӣҗн•ҙ мЈјм„ёмҡ”!`;
      break;
    case 'logout':
      // [лёҢл Ҳмқёл¬ён•ҙл Ҙ] нҷҚкёёлҸҷ н•ҷмғқмқҙ н•ҷмҠөмқ„ мҷ„лЈҢн•ҳмҳҖм–ҙмҡ”! л§Һмқҙ м№ӯм°¬ н•ҙмЈјм„ёмҡ”!
      // мЈјк°„ лҰ¬нҸ¬нҠё л§ҒнҒ¬ мғқм„ұ (grade м •ліҙк°Җ мһҲмңјл©ҙ нҸ¬н•Ё)
      const grade = additionalInfo.grade || '';
      const weekStart = getWeekStart();
      const reportUrl = `https://brainmoon.kr/my-learning?grade=${encodeURIComponent(grade)}&name=${encodeURIComponent(studentName)}&weekly=true&weekStart=${weekStart}&shared=true`;

      // URL лӢЁм¶• м—Ҷмқҙ мӣҗліё URL мӮ¬мҡ© (LMS л°ңмҶЎмқҙлқј мһҘл¬ё OK)
      // 2мӨ„ кіөл°ұмңјлЎң лҜёлҰ¬ліҙкё° мӨ‘ліө л°©м§Җ мӢңлҸ„
      message = `\n\n[лёҢл Ҳмқёл¬ён•ҙл Ҙ] ${studentName} н•ҷмғқмқҙ н•ҷмҠөмқ„ мҷ„лЈҢн•ҳмҳҖм–ҙмҡ”! л§Һмқҙ м№ӯм°¬ н•ҙмЈјм„ёмҡ”!\nл§ҒнҒ¬лҘј нҒҙлҰӯн•ҳл©ҙ н•ҷмҠө лҰ¬нҸ¬нҠёлҘј ліј мҲҳ мһҲм–ҙмҡ”!\n${reportUrl}`;
      break;
    case 'complete':
      // [лёҢл Ҳмқёл¬ён•ҙмӣҗ] нҷҚкёёлҸҷ н•ҷмғқ "лҜёмјҲлһҖм ӨлЎң" н•ҷмҠө мҷ„лЈҢ!
      let unitTitle = additionalInfo.unitTitle || additionalInfo.unitKey || 'лӢЁмӣҗ';
      // кё°ліё л©”мӢңм§Җ (лӢЁмӣҗлӘ… м ңмҷё) л°”мқҙнҠё кі„мӮ°
      const baseMsg = `[лёҢл Ҳмқёл¬ён•ҙмӣҗ] ${studentName} н•ҷмғқ "" н•ҷмҠө мҷ„лЈҢ!`;
      const baseBytes = getByteLength(baseMsg);
      const availableBytes = 90 - baseBytes - 6; // м—¬мң л¶„ 6л°”мқҙнҠё
      // лӢЁмӣҗлӘ…мқҙ кёёл©ҙ м¶•м•Ҫ
      if (getByteLength(unitTitle) > availableBytes) {
        unitTitle = truncateUnitTitle(unitTitle, availableBytes - 6); // ... нҸ¬н•Ё
      }
      message = `[лёҢл Ҳмқёл¬ён•ҙмӣҗ] ${studentName} н•ҷмғқ "${unitTitle}" н•ҷмҠө мҷ„лЈҢ!`;
      break;
    default:
      message = `[лёҢл Ҳмқёл¬ён•ҙмӣҗ] ${studentName} н•ҷмғқ м•ҢлҰј`;
  }

  return await sendSMS(parentPhone, message);
}

// ліёмӮ¬ кҙҖлҰ¬мһҗ м•ҢлҰј мӨ‘ліө л°©м§Җмҡ© мәҗмӢң (5л¶„)
const hqNotifyCache = new Map();

// ліёмӮ¬ кҙҖлҰ¬мһҗ м•ҢлҰј л°ңмҶЎ н•ЁмҲҳ (лӘЁл“  н•ҷмғқ мғҒнҷ© мҲҳмӢ )
async function sendHQAdminNotification(studentName, grade, type, additionalInfo = {}) {
  if (!HQ_ADMIN_PHONES || HQ_ADMIN_PHONES.length === 0) {
    return;
  }

  // н•ҷмҠөмҷ„лЈҢ(complete)мқј л•Ң мӨ‘ліө л°ңмҶЎ л°©м§Җ (5л¶„)
  if (type === 'complete' && additionalInfo.unitKey) {
    const cacheKey = `hq-complete:${grade}:${studentName}:${additionalInfo.unitKey}`;
    if (hqNotifyCache.has(cacheKey)) {
      console.log(`рҹ“ұ [ліёмӮ¬м•ҢлҰј] мӨ‘ліө л°©м§Җ: ${grade} ${studentName} ${additionalInfo.unitKey} (5л¶„ лӮҙ мқҙлҜё л°ңмҶЎлҗЁ)`);
      return;
    }
    // мҰүмӢң мәҗмӢңм—җ м¶”к°Җ (лҸҷкё°)
    hqNotifyCache.set(cacheKey, Date.now());
    setTimeout(() => hqNotifyCache.delete(cacheKey), 5 * 60 * 1000); // 5л¶„ нӣ„ мӮӯм ң
  }

  let message = '';
  const now = new Date();
  const kstOptions = { timeZone: 'Asia/Seoul', hour: '2-digit', minute: '2-digit', hour12: false };
  const timeStr = now.toLocaleTimeString('ko-KR', kstOptions);
  const academyName = additionalInfo.academyName || '';
  const schoolName = additionalInfo.school || '';
  const location = academyName || schoolName || '';

  switch (type) {
    case 'login':
      message = `[ліёмӮ¬м•ҢлҰј] ${location} ${grade} ${studentName} лЎңк·ёмқё (${timeStr})`;
      break;
    case 'logout':
      message = `[ліёмӮ¬м•ҢлҰј] ${location} ${grade} ${studentName} лЎңк·ём•„мӣғ (${timeStr})`;
      break;
    case 'complete':
      let unitTitle = additionalInfo.unitTitle || additionalInfo.unitKey || 'лӢЁмӣҗ';
      if (getByteLength(unitTitle) > 20) {
        unitTitle = truncateUnitTitle(unitTitle, 17);
      }
      message = `[ліёмӮ¬м•ҢлҰј] ${location} ${grade} ${studentName} "${unitTitle}" мҷ„лЈҢ`;
      break;
    default:
      message = `[ліёмӮ¬м•ҢлҰј] ${location} ${grade} ${studentName} м•ҢлҰј`;
  }

  // лӘЁл“  ліёмӮ¬ кҙҖлҰ¬мһҗм—җкІҢ л°ңмҶЎ
  for (const phone of HQ_ADMIN_PHONES) {
    sendSMS(phone, message).catch(err => console.error('ліёмӮ¬ м•ҢлҰј л°ңмҶЎ мӢӨнҢЁ:', err));
  }
}

