// ===== мҪҳн…җмё  нҢҢмқјм—җм„ң лӢЁмӣҗ м ңлӘ© к°Җм ёмҳӨкё° =====
const contentTitleCache = new Map(); // мҪҳн…җмё  м ңлӘ© мәҗмӢң

function getContentTitle(unitKey, unitPath) {
  // мәҗмӢң нҷ•мқё
  if (contentTitleCache.has(unitKey)) {
    return contentTitleCache.get(unitKey);
  }

  try {
    // unitPathм—җм„ң content нҢҢмқј кІҪлЎң м¶”м¶ң
    // ./BRAINUP/science/deep_bio_01.html -> ./public/BRAINUP/science/deep_bio_content.js
    const match = unitPath.match(/\.\/BRAINUP\/([^\/]+)\/([^_]+(?:_[^_]+)?)_(\d+)\.html/);
    if (!match) return null;

    const [, folder, prefix, unitNo] = match;
    // prefix: bio, fit_bio, deep_bio л“ұ
    const contentFile = path.join(__dirname, 'public', 'BRAINUP', folder, `${prefix}_content.js`);

    if (!fs.existsSync(contentFile)) return null;

    const content = fs.readFileSync(contentFile, 'utf8');

    // unitKeyмқҳ title м°ҫкё° (мҳҲ: deep_bio_01: { ... title: '...' })
    const titleRegex = new RegExp(`${unitKey}:\\s*\\{[^}]*title:\\s*['"]([^'"]+)['"]`, 's');
    const titleMatch = content.match(titleRegex);

    if (titleMatch && titleMatch[1]) {
      contentTitleCache.set(unitKey, titleMatch[1]);
      return titleMatch[1];
    }

    return null;
  } catch (error) {
    console.error(`мҪҳн…җмё  м ңлӘ© к°Җм ёмҳӨкё° мҳӨлҘҳ (${unitKey}):`, error.message);
    return null;
  }
}

// ===== к°„лӢЁн•ң л©”лӘЁлҰ¬ мәҗмӢң =====
const cache = new Map();
const CACHE_TTL = 30000; // 30мҙҲ

function getCacheKey(prefix, params) {
  return `${prefix}:${JSON.stringify(params)}`;
}

function getCache(key) {
  const cached = cache.get(key);
  if (!cached) return null;

  const now = Date.now();
  if (now > cached.expiry) {
    cache.delete(key);
    return null;
  }

  return cached.data;
}

function setCache(key, data, ttl = CACHE_TTL) {
  cache.set(key, {
    data,
    expiry: Date.now() + ttl
  });
}

function clearCacheByPrefix(prefix) {
  for (const key of cache.keys()) {
    if (key.startsWith(prefix)) {
      cache.delete(key);
    }
  }
}

