// вң… н•ҷмӣҗмҡ© кҙҖлҰ¬мһҗ лЎңк·ёмқё мІҳлҰ¬ (POST)
app.post("/academy-admin-login", async (req, res) => {
  try {
    const { academyName, name, phone } = req.body;
    console.log("рҹ“Ҙ [POST] /academy-admin-login:", { academyName, name, phone });

    // DBм—җм„ң н•ҷмӣҗмҡ© кҙҖлҰ¬мһҗ м°ҫкё°
    const admin = await Admin.findOne({
      academyName,
      name,
      phone,
      userType: "academy",
      deleted: { $ne: true }
    });

    if (!admin) {
      console.log("вқҢ н•ҷмӣҗ кҙҖлҰ¬мһҗ лЎңк·ёмқё мӢӨнҢЁ: мқјм№ҳн•ҳлҠ” кі„м • м—ҶмқҢ");
      return res.redirect("/academy-admin-login?error=invalid");
    }

    // мҠ№мқё лҢҖкё° мғҒнғңл©ҙ лЎңк·ёмқё л§үкё°
    if (admin.status === "pending") {
      console.log("вӣ” мҠ№мқё лҢҖкё° н•ҷмӣҗ кҙҖлҰ¬мһҗ лЎңк·ёмқё мӢңлҸ„:", admin.name);
      return res.redirect("/academy-admin-login?error=pending");
    }

    // л§Ҳм§Җл§ү лЎңк·ёмқё мӢңк°„ м—…лҚ°мқҙнҠё
    admin.lastLogin = new Date();
    await admin.save();

    // рҹ”Ҙ мҠҲнҚјкҙҖлҰ¬мһҗ мІҙнҒ¬ (role: "super" лҳҗлҠ” isSuper: true)
    console.log("рҹ”Қ [DEBUG] admin.role:", admin.role, "admin.isSuper:", admin.isSuper);
    const isSuperAdmin = admin.role === "super" || admin.isSuper === true;
    console.log("рҹ”Қ [DEBUG] isSuperAdmin кІ°кіј:", isSuperAdmin);

    // м„ём…ҳм—җ кҙҖлҰ¬мһҗ м •ліҙ м ҖмһҘ
    req.session.admin = {
      id: admin._id.toString(),
      academyName: admin.academyName,
      name: admin.name,
      role: admin.role || "teacher",
      userType: "academy",
      isSuper: isSuperAdmin
    };

    // рҹ”№ мҠҲнҚјкҙҖлҰ¬мһҗ мЎ°нҡҢ лӘЁл“ң м„ём…ҳ м •лҰ¬ (лёҢлһңм№ҳ кҙҖлҰ¬мһҗ м§Ғм ‘ лЎңк·ёмқё мӢң)
    if (req.session.viewingBranch) {
      delete req.session.viewingBranch;
    }

    // рҹ”Ҙ н•ҷмӣҗмҡ© кҙҖлҰ¬мһҗ мҝ нӮӨ м„Өм • (м„ём…ҳ л§ҢлЈҢ мӢң лҰ¬лӢӨмқҙл үнҠёмҡ©)
    res.cookie("adminType", "academy", { maxAge: 30 * 24 * 60 * 60 * 1000, httpOnly: true });

    console.log("вң… н•ҷмӣҗ кҙҖлҰ¬мһҗ лЎңк·ёмқё м„ұкіө:", admin.academyName, admin.name, isSuperAdmin ? "(мҠҲнҚјкҙҖлҰ¬мһҗ)" : "");

    // рҹ”Ҙ мҠҲнҚјкҙҖлҰ¬мһҗл©ҙ PIN мқёмҰқ нҺҳмқҙм§ҖлЎң мқҙлҸҷ (мҠҲнҚјкҙҖлҰ¬мһҗ лҢҖмӢңліҙл“ң м ‘к·јмҡ©)
    if (isSuperAdmin) {
      console.log("рҹ”җ н•ҷмӣҗ мҠҲнҚјкҙҖлҰ¬мһҗ PIN мқёмҰқ н•„мҡ”:", admin.name);
      req.session.superPinRequired = true;
      return res.redirect("/super/pin");
    }

    // рҹ”Ҙ н•ҷмӣҗлӘ…мқҙ "м–ҙл“ңлҜј"мқҙл©ҙ мҠҲнҚјкҙҖлҰ¬мһҗ лҢҖмӢңліҙл“ңлЎң л°”лЎң мқҙлҸҷ
    if (academyName === "м–ҙл“ңлҜј") {
      console.log("рҹҸў м–ҙл“ңлҜј кі„м • вҶ’ мҠҲнҚјкҙҖлҰ¬мһҗ лҢҖмӢңліҙл“ңлЎң мқҙлҸҷ");
      req.session.admin.isSuper = true;  // мҠҲнҚјкҙҖлҰ¬мһҗ к¶Ңн•ң л¶Җм—¬
      req.session.superPinVerified = true;
      return res.redirect("/super/dashboard?type=academy");
    }

    // рҹ”Ҙ мқјл°ҳ н•ҷмӣҗ кҙҖлҰ¬мһҗлҠ” PIN мқёмҰқ м—Ҷмқҙ л°”лЎң н•ҷмӣҗмҡ© лёҢлһңм№ҳ лҢҖмӢңліҙл“ңлЎң мқҙлҸҷ
    console.log("рҹҸў н•ҷмӣҗ кҙҖлҰ¬мһҗ вҶ’ н•ҷмӣҗмҡ© лёҢлһңм№ҳ лҢҖмӢңліҙл“ңлЎң мқҙлҸҷ (PIN мғқлһө)");
    req.session.adminPinVerified = true;
    return res.redirect("/academy/dashboard");
  } catch (err) {
    console.error("вқҢ /academy-admin-login м—җлҹ¬:", err);
    res.status(500).send("н•ҷмӣҗ кҙҖлҰ¬мһҗ лЎңк·ёмқё мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.");
  }
});

