// вң… л“ұлЎқлҗң н•ҷмӣҗ лӘ©лЎқ мЎ°нҡҢ API (н•ҷмӣҗмҡ© лЎңк·ёмқё/нҡҢмӣҗк°Җмһ…мҡ©)
app.get("/api/academies", async (req, res) => {
  try {
    // Admin н…Ңмқҙлё”м—җм„ң н•ҷмӣҗмҡ© academyName лӘ©лЎқ к°Җм ёмҳӨкё°
    const adminAcademies = await Admin.find({
      deleted: { $ne: true },
      userType: "academy"
    }).distinct("academyName");

    // User н…Ңмқҙлё”м—җм„ң н•ҷмӣҗмҡ© academyName лӘ©лЎқ к°Җм ёмҳӨкё°
    const userAcademies = await User.find({
      deleted: { $ne: true },
      userType: "academy"
    }).distinct("academyName");

    // л‘җ лӘ©лЎқ н•©м№ҳкё° (мӨ‘ліө м ңкұ°)
    const allAcademies = [...new Set([...adminAcademies, ...userAcademies])];

    // л№Ҳ к°’ м ңкұ° л°Ҹ м •л ¬
    const academies = allAcademies
      .filter(name => name && name.trim() && name !== "м–ҙл“ңлҜј")
      .sort((a, b) => a.localeCompare(b, "ko"));

    res.json({ ok: true, academies });
  } catch (err) {
    console.error("вқҢ /api/academies м—җлҹ¬:", err);
    res.json({ ok: false, academies: [] });
  }
});

// вң… л“ұлЎқлҗң н•ҷкөҗ лӘ©лЎқ мЎ°нҡҢ API (лЎңк·ёмқё/нҡҢмӣҗк°Җмһ…мҡ©)
app.get("/api/schools", async (req, res) => {
  try {
    // Admin н…Ңмқҙлё”м—җм„ң academyName лӘ©лЎқ к°Җм ёмҳӨкё°
    const adminSchools = await Admin.find({ deleted: { $ne: true } }).distinct("academyName");

    // User н…Ңмқҙлё”м—җм„ң school лӘ©лЎқ к°Җм ёмҳӨкё°
    const userSchools = await User.find({ deleted: { $ne: true } }).distinct("school");

    // л‘җ лӘ©лЎқ н•©м№ҳкё° (мӨ‘ліө м ңкұ°)
    const allSchools = [...new Set([...adminSchools, ...userSchools])];

    // л№Ҳ к°’ м ңкұ° л°Ҹ м •л ¬
    const schools = allSchools
      .filter(name => name && name.trim() && name !== "м–ҙл“ңлҜј")
      .sort((a, b) => a.localeCompare(b, "ko"));

    res.json({ ok: true, schools });
  } catch (err) {
    console.error("вқҢ /api/schools м—җлҹ¬:", err);
    res.json({ ok: false, schools: [] });
  }
});

