// вң… лёҢлһңм№ҳ кҙҖлҰ¬мһҗ PIN кІҖмҰқ
app.post("/admin/pin/verify", async (req, res) => {
  // кҙҖлҰ¬мһҗк°Җ м•„лӢҲл©ҙ лЎңк·ёмқё нҺҳмқҙм§ҖлЎң
  if (!req.session.admin) {
    const isAcademyAdmin = req.cookies && req.cookies.adminType === "academy";
    return res.redirect("/academy-admin-login");
  }

  const { pin } = req.body;
  const adminId = req.session.admin.id;

  try {
    const admin = await Admin.findById(adminId);

    if (admin && admin.pin === pin) {
      console.log("вң… лёҢлһңм№ҳ кҙҖлҰ¬мһҗ PIN мқёмҰқ м„ұкіө:", req.session.admin.name);
      req.session.adminPinVerified = true;
      req.session.adminPinRequired = false;
      return res.redirect("/admin/dashboard");
    } else {
      console.log("вқҢ лёҢлһңм№ҳ кҙҖлҰ¬мһҗ PIN мқёмҰқ мӢӨнҢЁ");
      return res.redirect("/admin/pin?error=1");
    }
  } catch (err) {
    console.error("вқҢ PIN кІҖмҰқ мҳӨлҘҳ:", err);
    return res.redirect("/admin/pin?error=1");
  }
});

