app.post("/api/super/whale-badges/update", requireSuperAdmin, async (req, res) => {
  try {
    const { grade, name, totalCoins, usedCoins } = req.body;

    if (!grade || !name) {
      return res.json({ ok: false, message: 'н•ҷл…„кіј мқҙлҰ„мқҙ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    const result = await UserProgress.updateOne(
      { grade, name },
      {
        $set: {
          'vocabularyQuiz.totalCoins': totalCoins || 0,
          'vocabularyQuiz.usedCoins': usedCoins || 0,
          'vocabularyQuiz.lastRankUpdate': new Date()
        }
      }
    );

    if (result.matchedCount === 0) {
      return res.json({ ok: false, message: 'н•ҙлӢ№ н•ҷмғқмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.' });
    }

    console.log(`вң… кі лһҳ лұғм§Җ мҲҳм •: ${grade} ${name} - totalCoins: ${totalCoins}, usedCoins: ${usedCoins}`);
    res.json({ ok: true });
  } catch (err) {
    console.error("вқҢ кі лһҳ лұғм§Җ мҲҳм • мҳӨлҘҳ:", err);
    res.status(500).json({ ok: false, message: err.message });
  }
});

