app.put("/api/book-orders/:id", requireSuperAdmin, async (req, res) => {
  try {
    const { id } = req.params;
    const { academyId, academyName, orderDate, literacyBookCount, creativeBookCount, confirmed, shipped } = req.body;

    const order = await BookOrder.findById(id);
    if (!order) {
      return res.status(404).json({ ok: false, message: "мЈјл¬ёмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ" });
    }

    if (academyId !== undefined) order.academyId = academyId;
    if (academyName !== undefined) order.academyName = academyName;
    if (orderDate !== undefined) order.orderDate = new Date(orderDate);
    if (literacyBookCount !== undefined) order.literacyBookCount = parseInt(literacyBookCount) || 0;
    if (creativeBookCount !== undefined) order.creativeBookCount = parseInt(creativeBookCount) || 0;
    if (confirmed !== undefined) order.confirmed = confirmed;
    if (shipped !== undefined) order.shipped = shipped;

    await order.save();
    console.log(`вң… көҗмһ¬ мЈјл¬ё мҲҳм •: ${order.academyName}`);
    res.json({ ok: true, order });
  } catch (err) {
    console.error("вқҢ көҗмһ¬ мЈјл¬ё мҲҳм • мҳӨлҘҳ:", err);
    res.status(500).json({ ok: false, message: err.message });
  }
});

