// лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ© н•ҷмҠө мқҙл Ҙ лҚ°мқҙн„° API
app.get("/api/branch/logs", requireAdminLogin, async (req, res) => {
  try {
    const { grade, name } = req.query;

    if (!grade || !name) {
      return res.status(400).json({
        ok: false,
        message: "grade, name нҢҢлқјлҜён„°к°Җ н•„мҡ”н•©лӢҲлӢӨ."
      });
    }

    const logs = await LearningLog.find({ grade, name, deleted: { $ne: true } })
      .sort({ timestamp: -1 })
      .lean();

    return res.json({
      ok: true,
      count: logs.length,
      logs
    });
  } catch (err) {
    console.error("вқҢ /api/branch/logs м—җлҹ¬:", err);
    res.status(500).json({ ok: false, message: "м„ңлІ„ мҳӨлҘҳ" });
  }
});

// лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ© AI м¶”мІңкіјм ң лӘ©лЎқ API (н•ҷмӣҗлі„ н•„н„°л§Ғ)
app.get('/api/branch/ai-tasks', requireAdminLogin, async (req, res) => {
  try {
    const admin = req.session.admin;
    if (!admin) {
      return res.status(401).json({ ok: false, message: "кҙҖлҰ¬мһҗ м„ём…ҳ м—ҶмқҢ" });
    }

    const academyName = admin.academyName;

    // н•ҙлӢ№ н•ҷмӣҗ н•ҷмғқл“Өмқҳ UserProgressл§Ң мЎ°нҡҢ
    const allProgress = await UserProgress.find({ school: academyName });

    const aiTasksList = [];

    for (const progress of allProgress) {
      const aiTasks = progress.studyRoom?.assignedTasks?.filter(t => t.isAI) || [];

      aiTasks.forEach(task => {
        aiTasksList.push({
          grade: progress.grade,
          name: progress.name,
          school: progress.school || academyName,
          taskTitle: task.title,
          series: task.series,
          field: task.field || task.domain,
          subject: task.subject,
          assignedAt: task.assignedAt,
          status: task.status,
          unitId: task.id || task.unitId
        });
      });
    }

    // л¶Җм—¬мӢңк°„ кё°мӨҖ мөңмӢ мҲң м •л ¬
    aiTasksList.sort((a, b) => {
      const dateA = new Date(a.assignedAt || 0);
      const dateB = new Date(b.assignedAt || 0);
      return dateB - dateA;
    });

    res.json({
      ok: true,
      tasks: aiTasksList,
      total: aiTasksList.length,
      academyName
    });

  } catch (error) {
    console.error('AI м¶”мІңкіјм ң лӘ©лЎқ мЎ°нҡҢ мҳӨлҘҳ (лёҢлһңм№ҳ):', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

