// кҙҖлҰ¬мһҗ лЎңк·ёмқё мІҳлҰ¬ (POST) - н•ҷкөҗмҡ©
app.post("/admin-login", async (req, res) => {
  try {
    const { academyName, grade, classNum, name, birth, phone } = req.body;
    console.log("рҹ“Ҙ [POST] /admin-login:", req.body);

    // рҹ”Ҙ мҠҲнҚјкҙҖлҰ¬мһҗ лЎңк·ёмқё мӢңлҸ„ м—¬л¶Җ нҷ•мқё (grade/classNum м—ҶмқҙлҸ„ лЎңк·ёмқё к°ҖлҠҘ)
    const isSuperLogin =
      academyName === "м–ҙл“ңлҜј" &&
      name === "м–ҙл“ңлҜј" &&
      birth === "830911" &&
      phone === "01012341234";

    // DBм—җм„ң кҙҖлҰ¬мһҗ м°ҫкё° (мҠҲнҚјкҙҖлҰ¬мһҗлҠ” grade/classNum м—Ҷмқҙ кІҖмғү)
    const query = isSuperLogin
      ? { academyName, name, birth, phone }
      : { academyName, grade, classNum, name, birth, phone };

    const admin = await Admin.findOne(query);

    if (!admin) {
      console.log("вқҢ кҙҖлҰ¬мһҗ лЎңк·ёмқё мӢӨнҢЁ: мқјм№ҳн•ҳлҠ” кі„м • м—ҶмқҢ");
      return res.redirect("/academy-admin-login?error=invalid");
    }

    // рҹ”’ мҠҲнҚјкҙҖлҰ¬мһҗк°Җ м•„лӢҢлҚ° мҠ№мқё лҢҖкё°л©ҙ лЎңк·ёмқё л§үкё°
    if (!isSuperLogin && admin.status === "pending") {
      console.log("вӣ” мҠ№мқё лҢҖкё° кҙҖлҰ¬мһҗ лЎңк·ёмқё мӢңлҸ„:", admin.name);
      return res.redirect("/academy-admin-login?error=pending");
    }

    // л§Ҳм§Җл§ү лЎңк·ёмқё мӢңк°„ м—…лҚ°мқҙнҠё
    admin.lastLogin = new Date();
    await admin.save();

    // м„ём…ҳм—җ кҙҖлҰ¬мһҗ м •ліҙ м ҖмһҘ (isSuper м—¬л¶Җ нҸ¬н•Ё)
    req.session.admin = {
      id: admin._id.toString(),
      academyName: admin.academyName,
      name: admin.name,
      role: admin.role,
      grade: admin.grade || "",       // вң… м„ мғқлӢҳ н•ҷл…„ м¶”к°Җ
      classNum: admin.classNum || "", // вң… м„ мғқлӢҳ л°ҳ м¶”к°Җ
      isSuper: isSuperLogin,   // вң… м—¬кё°!
    };

    // рҹ”Ҙ н•ҷкөҗмҡ© кҙҖлҰ¬мһҗ мҝ нӮӨ м„Өм • (м„ём…ҳ л§ҢлЈҢ мӢң лҰ¬лӢӨмқҙл үнҠёмҡ©)
    res.cookie("adminType", "school", { maxAge: 30 * 24 * 60 * 60 * 1000, httpOnly: true });

    console.log(
      "вң… кҙҖлҰ¬мһҗ лЎңк·ёмқё м„ұкіө:",
      admin.academyName,
      admin.name,
      isSuperLogin ? "(мҠҲнҚјкҙҖлҰ¬мһҗ)" : ""
    );

    // рҹ”Җ л¶„кё°: мҠҲнҚјкҙҖлҰ¬мһҗ / мқјл°ҳ лёҢлһңм№ҳ кҙҖлҰ¬мһҗ
    if (isSuperLogin) {
      return res.redirect("/super/dashboard");
    } else {
      // рҹ”җ лёҢлһңм№ҳ кҙҖлҰ¬мһҗ PINмқҙ м—Ҷмңјл©ҙ мғқл…„мӣ”мқјлЎң мһҗлҸҷ м„Өм •
      if (!admin.pin) {
        admin.pin = admin.birth; // мғқл…„мӣ”мқј 6мһҗлҰ¬лҘј мҙҲкё° PINмңјлЎң м„Өм •
        await admin.save();
        console.log("рҹ”җ лёҢлһңм№ҳ кҙҖлҰ¬мһҗ PIN мһҗлҸҷ м„Өм • (мғқл…„мӣ”мқј):", admin.name, admin.pin);
      }
      // н•ӯмғҒ PIN мһ…л Ҙ нҺҳмқҙм§ҖлЎң
      req.session.adminPinRequired = true;
      return res.redirect("/admin/pin");
    }
  } catch (err) {
    console.error("вқҢ /admin-login м—җлҹ¬:", err);
    res.status(500).send("кҙҖлҰ¬мһҗ лЎңк·ёмқё мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.");
  }
});




