            <input type="number" id="creativeBookCount" value="0" min="0" onchange="calcCreativeTotal()" oninput="calcCreativeTotal()" style="width:100%; padding:10px; border:1px solid #ddd; border-radius:8px; font-size:14px; box-sizing:border-box;" />
