// вң… лЎңк·ём•„мӣғ (GET: м• лӢҲл©”мқҙм…ҳ нҺҳмқҙм§ҖлЎң)
app.get("/logout", async (req, res) => {
  // рҹ“ұ лЎңк·ём•„мӣғ м „ н•ҷл¶ҖлӘЁ м•ҢлҰј л°ңмҶЎ
  if (req.session && req.session.user) {
    try {
      const { name, grade, school, academyName } = req.session.user;
      const studentUser = await User.findOne({ grade, name, deleted: { $ne: true } });
      if (studentUser && studentUser.parentPhone && studentUser.parentNotify !== false) {
        sendParentNotification(name, studentUser.parentPhone, 'logout', { grade })
          .catch(err => console.error('н•ҷл¶ҖлӘЁ м•ҢлҰј(лЎңк·ём•„мӣғ) мӢӨнҢЁ:', err));
      }
      // рҹ“ұ ліёмӮ¬ кҙҖлҰ¬мһҗ м•ҢлҰј л°ңмҶЎ (лЎңк·ём•„мӣғ)
      sendHQAdminNotification(name, grade, 'logout', { school, academyName });
    } catch (notifyErr) {
      console.warn("рҹ“ұ лЎңк·ём•„мӣғ м•ҢлҰј л°ңмҶЎ мӢӨнҢЁ:", notifyErr.message);
    }
  }

  req.session.destroy((err) => {
    if (err) {
      console.log("вқ— м„ём…ҳ мў…лЈҢ мҳӨлҘҳ:", err);
    }

    res.clearCookie("connect.sid", {
      path: "/",
      httpOnly: true,
      secure: false,
    });

    res.redirect("/logout.html");
  });
});

// рҹ“ұ мһҗлҸҷ лЎңк·ём•„мӣғ API (2мӢңк°„ л№„нҷңлҸҷ + н•ҷмҠөмҷ„лЈҢк°Җ мһҲлҠ” кІҪмҡ°м—җл§Ң нҳём¶ңлҗЁ)
app.post("/api/auto-logout", async (req, res) => {
  const { grade, name, reason, hasCompletedLearning } = req.body;

  if (!grade || !name) {
    return res.status(400).json({ success: false, message: 'н•ҷл…„/мқҙлҰ„ н•„мҡ”' });
  }

  // н•ҷмҠөмҷ„лЈҢк°Җ м—Ҷмңјл©ҙ мІҳлҰ¬н•ҳм§Җ м•ҠмқҢ
  if (!hasCompletedLearning) {
    console.log(`вҸӯпёҸ [мһҗлҸҷ лЎңк·ём•„мӣғ] ${grade} ${name} - н•ҷмҠөмҷ„лЈҢ м—ҶмқҢ, мІҳлҰ¬ кұҙл„ҲлңҖ`);
    return res.json({ success: true, message: 'н•ҷмҠөмҷ„лЈҢ м—ҶмқҢ - мІҳлҰ¬ кұҙл„ҲлңҖ' });
  }

  console.log(`рҹ”„ [мһҗлҸҷ лЎңк·ём•„мӣғ] ${grade} ${name} - мӮ¬мң : ${reason || 'inactivity'}, н•ҷмҠөмҷ„лЈҢ: мһҲмқҢ`);

  try {
    // мҳӨлҠҳ лӮ м§ң
    const today = new Date().toISOString().split('T')[0];

    // мҳӨлҠҳ мқҙлҜё л°ңмҶЎн–ҲлҠ”м§Җ нҷ•мқё
    const alreadySent = await DailyReportSent.findOne({ grade, name, date: today });

    if (alreadySent) {
      console.log(`вҸӯпёҸ [мһҗлҸҷ лЎңк·ём•„мӣғ] ${grade} ${name} - мҳӨлҠҳ мқҙлҜё л°ңмҶЎлҗЁ, мҠӨнӮө`);
      return res.json({ success: true, message: 'мҳӨлҠҳ мқҙлҜё л°ңмҶЎлҗЁ - мҠӨнӮө' });
    }

    const studentUser = await User.findOne({ grade, name, deleted: { $ne: true } });

    if (studentUser) {
      // рҹ“ұ н•ҷл¶ҖлӘЁ м•ҢлҰј л°ңмҶЎ (лҰ¬нҸ¬нҠё URL нҸ¬н•Ё)
      if (studentUser.parentPhone && studentUser.parentNotify !== false) {
        sendParentNotification(name, studentUser.parentPhone, 'logout', { grade })
          .catch(err => console.error('н•ҷл¶ҖлӘЁ м•ҢлҰј(мһҗлҸҷ лЎңк·ём•„мӣғ+лҰ¬нҸ¬нҠё) мӢӨнҢЁ:', err));
      }

      // рҹ“ұ ліёмӮ¬ кҙҖлҰ¬мһҗ м•ҢлҰј л°ңмҶЎ
      sendHQAdminNotification(name, grade, 'logout', {
        school: studentUser.school,
        academyName: studentUser.academyName
      });

      // л°ңмҶЎ кё°лЎқ м ҖмһҘ
      await DailyReportSent.create({ grade, name, date: today, type: 'auto_logout' });

      console.log(`вң… [мһҗлҸҷ лЎңк·ём•„мӣғ] ${grade} ${name} SMS + лҰ¬нҸ¬нҠё л°ңмҶЎ мҷ„лЈҢ`);
    }

    res.json({ success: true, message: 'мһҗлҸҷ лЎңк·ём•„мӣғ + лҰ¬нҸ¬нҠё л°ңмҶЎ мҷ„лЈҢ' });
  } catch (err) {
    console.error('[мһҗлҸҷ лЎңк·ём•„мӣғ] мҳӨлҘҳ:', err);
    res.status(500).json({ success: false, message: 'м„ңлІ„ мҳӨлҘҳ' });
  }
});

