            // fit_/deep_/on_ м ‘л‘җм–ҙ мІҳлҰ¬: fit_bio_01 вҶ’ ['fit', 'bio', '01'], deep_bio_01 вҶ’ ['deep', 'bio', '01'], on_bio_01 вҶ’ ['on', 'bio', '01']
