app.post("/academy-register", async (req, res) => {
  try {
    const { academyName, grade, name, phone } = req.body;

    console.log("рҹ“© [POST] /academy-register мҡ”мІӯ:", academyName, grade, name, phone);

    // 1) н•„мҲҳк°’ мІҙнҒ¬
    if (!academyName || !grade || !name || !phone) {
      return res.status(400).send("н•„мҲҳ м •ліҙк°Җ л¶ҖмЎұн•©лӢҲлӢӨ.");
    }

    const cleanPhone = String(phone).replace(/\D/g, "").trim();

    // 2) м „нҷ”лІҲнҳё м „мІҙ мӨ‘ліө нҷ•мқё (н•ҷмӣҗмҡ©мқҖ м „нҷ”лІҲнҳё м „мІҙк°Җ мң лӢҲнҒ¬)
    const existing = await User.findOne({
      phone: cleanPhone,
      userType: "academy",
      deleted: { $ne: true }
    });

    if (existing) {
      console.log("вҡ  мқҙлҜё л“ұлЎқлҗң м „нҷ”лІҲнҳёмһ…лӢҲлӢӨ:", cleanPhone);
      return res.redirect("/academy.html?loginError=duplicate");
    }

    // 3) мғҲ н•ҷмӣҗмҡ© н•ҷмғқ мғқм„ұ
    const created = await User.create({
      academyName,
      grade,             // рҹ”№ н•ҷл…„ м¶”к°Җ
      name,
      phone: cleanPhone,
      pw: cleanPhone,        // рҹ”Ҙ м „нҷ”лІҲнҳё м „мІҙлҘј л№„л°ҖлІҲнҳёлЎң мӮ¬мҡ©
      userType: "academy",   // рҹ”№ н•ҷмӣҗмҡ© нғҖмһ…
      approved: false,
      status: "pending",     // кё°ліёк°’: мҠ№мқё м „
      deleted: false,
      createdAt: new Date(),
    });

    console.log("вң… [POST] н•ҷмӣҗмҡ© нҡҢмӣҗк°Җмһ… DB м ҖмһҘ мҷ„лЈҢ:", created.name, created.grade);

    // 4) нҡҢмӣҗк°Җмһ… м•ҢлҰј мқҙл©”мқј л°ңмҶЎ
    try {
      const mailOptions = {
        from: process.env.NAVER_EMAIL,
        to: "kukikukilove@naver.com",
        subject: `[н•ҷмӣҗмҡ© нҡҢмӣҗк°Җмһ…] ${academyName} - ${name}`,
        html: `
          <h2>рҹҸ« н•ҷмӣҗмҡ© нҡҢмӣҗк°Җмһ… м•ҢлҰј</h2>
          <table style="border-collapse: collapse; width: 100%; max-width: 500px;">
            <tr style="border-bottom: 1px solid #eee;">
              <td style="padding: 10px; font-weight: bold; width: 100px;">н•ҷмӣҗлӘ…</td>
              <td style="padding: 10px;">${academyName}</td>
            </tr>
            <tr style="border-bottom: 1px solid #eee;">
              <td style="padding: 10px; font-weight: bold;">н•ҷл…„</td>
              <td style="padding: 10px;">${grade}</td>
            </tr>
            <tr style="border-bottom: 1px solid #eee;">
              <td style="padding: 10px; font-weight: bold;">мқҙлҰ„</td>
              <td style="padding: 10px;">${name}</td>
            </tr>
            <tr style="border-bottom: 1px solid #eee;">
              <td style="padding: 10px; font-weight: bold;">м „нҷ”лІҲнҳё</td>
              <td style="padding: 10px;">${cleanPhone}</td>
            </tr>
            <tr>
              <td style="padding: 10px; font-weight: bold;">к°Җмһ…мқјмӢң</td>
              <td style="padding: 10px;">${new Date().toLocaleString('ko-KR')}</td>
            </tr>
          </table>
        `
      };
      await transporter.sendMail(mailOptions);
      console.log("рҹ“§ н•ҷмӣҗмҡ© нҡҢмӣҗк°Җмһ… м•ҢлҰј мқҙл©”мқј л°ңмҶЎ мҷ„лЈҢ");
    } catch (emailErr) {
      console.error("вҡ  мқҙл©”мқј л°ңмҶЎ мӢӨнҢЁ (нҡҢмӣҗк°Җмһ…мқҖ мҷ„лЈҢлҗЁ):", emailErr);
    }

    // 5) нҡҢмӣҗк°Җмһ… нӣ„ мҠ№мқё лҢҖкё° м•ҲлӮҙ
    return res.redirect("/academy.html?signup=pending");
  } catch (err) {
    console.error("вқҢ /academy-register мІҳлҰ¬ мӨ‘ мҳӨлҘҳ:", err);
    return res.status(500).send("нҡҢмӣҗк°Җмһ… мІҳлҰ¬ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.");
  }
});

