// рҹҸ« н•ҷмӣҗмҡ© лЎңк·ёмқё API
// ============================================
app.post("/academy-login", async (req, res) => {
  try {
    const { academyName, grade, name, phone } = req.body;
    const cleanPhone = String(phone || "").replace(/\D/g, "").trim();

    console.log("рҹ“Ҙ [POST] /academy-login:", academyName, grade, name, cleanPhone);

    // н•„мҲҳк°’ м—Ҷмңјл©ҙ л°”лЎң мӢӨнҢЁ
    if (!academyName || !grade || !name || !cleanPhone) {
      return res.redirect("/academy.html?loginError=1");
    }

    // н•ҷмӣҗмҡ© мӮ¬мҡ©мһҗ м°ҫкё° (н•ҷмӣҗлӘ… + н•ҷл…„ + мқҙлҰ„ + м „нҷ”лІҲнҳё м „мІҙ)
    const user = await User.findOne({
      academyName,
      grade,
      name,
      userType: "academy",
      deleted: { $ne: true },
      $or: [
        { pw: cleanPhone },
        { phone: cleanPhone },
      ],
    });

    if (!user) {
      console.log("вқҢ н•ҷмӣҗмҡ© лЎңк·ёмқё мӢӨнҢЁ: н•ҙлӢ№ мӮ¬мҡ©мһҗ м—ҶмқҢ");
      return res.redirect("/academy.html?loginError=1");
    }

    // рҹ”№ м§Җм җ нҶөм§ёлЎң нңҙм§Җ(лёҢлһңм№ҳ мӮӯм ң)лҗң кІҪмҡ°
    if (user.branchDeleted) {
      console.log("рҹҡ« лёҢлһңм№ҳ нңҙм§Җ мғҒнғң кі„м •:", user.name);
      return res.redirect("/academy.html?loginError=trashed");
    }

    // рҹ”№ к°ңмқё кі„м • нңҙм§Җ мғҒнғң
    if (user.deleted) {
      console.log("рҹҡ« нңҙм§Җ мғҒнғң кі„м •:", user.name);
      return res.redirect("/academy.html?loginError=trashed");
    }

    // рҹ”№ мҠ№мқё лҢҖкё° мғҒнғң(pending)л©ҙ м „мҡ© нҢқм—…
    if (user.status && user.status !== "approved") {
      console.log("вҸі мҠ№мқё лҢҖкё° кі„м •:", user.name);
      return res.redirect("/academy.html?loginError=pending");
    }

    // вң… м •мғҒ лЎңк·ёмқё
    req.session.user = {
      _id: user._id,
      name: user.name,
      grade: user.grade,
      academyName: user.academyName,
      userType: "academy",
      role: "student",
      assignedSeries: user.assignedSeries || [],
    };

    await User.updateOne(
      { _id: user._id },
      { $set: { lastLogin: new Date() } }
    );

    console.log("вң… н•ҷмӣҗмҡ© лЎңк·ёмқё м„ұкіө:", user.name, user.grade, user.academyName);

    // рҹ“ұ н•ҷл¶ҖлӘЁ м•ҢлҰј л°ңмҶЎ (н•ҷмӣҗ лЎңк·ёмқё)
    if (user.parentPhone && user.parentNotify !== false) {
      sendParentNotification(user.name, user.parentPhone, 'login', { grade: user.grade })
        .catch(err => console.error('н•ҷл¶ҖлӘЁ м•ҢлҰј мӢӨнҢЁ:', err));
    }

    // рҹ“ұ ліёмӮ¬ кҙҖлҰ¬мһҗ м•ҢлҰј л°ңмҶЎ (н•ҷмӣҗ лЎңк·ёмқё)
    sendHQAdminNotification(user.name, user.grade, 'login', { academyName: user.academyName });

    // н•ҷмӣҗмҡ©лҸ„ лҸҷмқјн•ң л©”лүҙ нҺҳмқҙм§ҖлЎң мқҙлҸҷ
    // brain_libraryм—җм„ң лЎңк·ёмқён•ң кІҪмҡ° м°Ҫмһ‘ лҸ„м„ңкҙҖ нҢқм—… мһҗлҸҷ мҳӨн”Ҳ
    const { loginSource } = req.body;
    const NEXT_URL = loginSource === "brain_library"
      ? "/menu.html?popup=creative-library"
      : "/menu.html";
    return res.redirect(
      "/loading.html?to=" + encodeURIComponent(NEXT_URL)
    );
  } catch (err) {
    console.error("вқҢ /academy-login мІҳлҰ¬ мӨ‘ мҳӨлҘҳ:", err);
    return res.redirect("/academy.html?loginError=1");
  }
});

// вң… м„ём…ҳ м •ліҙ мЎ°нҡҢ API (нҒҙлқјмқҙм–ёнҠём—җм„ң мӮ¬мҡ©)
