// вң… кҙҖлҰ¬мһҗ(admin) м„ём…ҳ м •ліҙ мЎ°нҡҢ API
app.get("/api/admin-session", async (req, res) => {
  // рҹ”№ мҠҲнҚјкҙҖлҰ¬мһҗ мЎ°нҡҢ лӘЁл“ңмқё кІҪмҡ°
  if (req.session && req.session.viewingBranch) {
    const viewing = req.session.viewingBranch;
    try {
      const admin = await Admin.findById(viewing._id).lean();
      return res.json({
        ok: true,
        admin: {
          id: viewing._id,
          academyName: viewing.academyName,
          name: viewing.name,
          userType: "academy",
          viewMode: "super",
          seriesApproved: admin ? admin.seriesApproved : false,
          approvedSeries: admin ? (admin.approvedSeries || []) : []
        }
      });
    } catch (err) {
      return res.json({
        ok: true,
        admin: {
          id: viewing._id,
          academyName: viewing.academyName,
          name: viewing.name,
          userType: "academy",
          viewMode: "super",
          seriesApproved: false,
          approvedSeries: viewing.approvedSeries || []
        }
      });
    }
  }

  if (req.session && req.session.admin) {
    // DBм—җм„ң мөңмӢ  seriesApproved, approvedSeries м •ліҙ к°Җм ёмҳӨкё°
    try {
      const admin = await Admin.findById(req.session.admin.id).lean();
      return res.json({
        ok: true,
        admin: {
          ...req.session.admin,
          seriesApproved: admin ? admin.seriesApproved : false,
          approvedSeries: admin ? (admin.approvedSeries || []) : []
        }
      });
    } catch (err) {
      return res.json({
        ok: true,
        admin: {
          ...req.session.admin,
          seriesApproved: false,
          approvedSeries: []
        }
      });
    }
  } else {
    return res.json({ ok: false, admin: null });
  }
});

