// л¬ёмһҘ мҷ„лҸ… мғҒнғң м ҖмһҘ
app.post('/api/sentence-read/save', async (req, res) => {
  try {
    const { grade, name, phone, unit, selectedSentences, completedParagraphs, readingTime } = req.body;

    if (!grade || !name || !unit) {
      return res.json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ лҲ„лқҪлҗҳм—ҲмҠөлӢҲлӢӨ.' });
    }

    const filter = { grade, name, phone: phone || '', unit };
    const update = {
      selectedSentences: selectedSentences || [],
      completedParagraphs: completedParagraphs || [],
      readingTime: readingTime || {},
      updatedAt: new Date()
    };

    const result = await SentenceRead.findOneAndUpdate(filter, update, { upsert: true, new: true });
    res.json({ ok: true, data: result });
  } catch (err) {
    console.error('[sentence-read/save] мҳӨлҘҳ:', err);
    res.json({ ok: false, message: err.message });
  }
});

// л¬ёмһҘ мҷ„лҸ… мғҒнғң л¶Ҳлҹ¬мҳӨкё°
app.get('/api/sentence-read/load', async (req, res) => {
  try {
    const { grade, name, phone, unit } = req.query;

    if (!grade || !name || !unit) {
      return res.json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ лҲ„лқҪлҗҳм—ҲмҠөлӢҲлӢӨ.' });
    }

    const data = await SentenceRead.findOne({ grade, name, phone: phone || '', unit });

    if (data) {
      res.json({ ok: true, data });
    } else {
      res.json({ ok: true, data: null });
    }
  } catch (err) {
    console.error('[sentence-read/load] мҳӨлҘҳ:', err);
    res.json({ ok: false, message: err.message });
  }
});

// вң… л§һм¶ӨлІ• кІҖмӮ¬ API
app.post("/api/spell-check", async (req, res) => {
  console.log("вң… [POST] /api/spell-check нҳём¶ң");

  const { text } = req.body;

  if (!text || text.trim().length === 0) {
    return res.status(400).json({ error: "н…ҚмҠӨнҠёлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”." });
  }

  try {
    const OpenAI = require('openai');
    const openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY
    });

    console.log("рҹӨ– OpenAI APIлЎң л§һм¶ӨлІ• кІҖмӮ¬ мӢңмһ‘...");

    // OpenAI API нҳём¶ң
    const response = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: "лӢ№мӢ мқҖ н•ңкөӯм–ҙ л§һм¶ӨлІ• л°Ҹ лқ„м–ҙм“°кё° м „л¬ёк°Җмһ…лӢҲлӢӨ. мЈјм–ҙм§„ н…ҚмҠӨнҠёмқҳ л§һм¶ӨлІ•кіј лқ„м–ҙм“°кё° мҳӨлҘҳлҘј м°ҫм•„ мҲҳм •н•ҙмЈјм„ёмҡ”."
        },
        {
          role: "user",
          content: `лӢӨмқҢ н…ҚмҠӨнҠёмқҳ л§һм¶ӨлІ•кіј лқ„м–ҙм“°кё° мҳӨлҘҳлҘј м°ҫм•„мЈјм„ёмҡ”. мҳӨлҘҳк°Җ мһҲлӢӨл©ҙ JSON нҳ•мӢқмңјлЎң мқ‘лӢөн•ҳкі , м—ҶлӢӨл©ҙ "мҳӨлҘҳ м—ҶмқҢ"мқҙлқјкі л§Ң лӢөн•ҙмЈјм„ёмҡ”.

н…ҚмҠӨнҠё: "${text}"

JSON нҳ•мӢқ:
{
  "has_errors": true,
  "errors": [
    {"wrong": "мһҳлӘ»лҗңл¶Җл¶„", "correct": "мҳ¬л°”лҘёл¶Җл¶„", "type": "лқ„м–ҙм“°кё°" or "л§һм¶ӨлІ•"}
  ],
  "corrected_text": "м „мІҙ мҲҳм •лҗң н…ҚмҠӨнҠё"
}`
        }
      ],
      temperature: 0.3,
      max_tokens: 2000
    });

    const aiResponse = response.choices[0].message.content;
    console.log("рҹӨ– OpenAI мқ‘лӢө:", aiResponse.substring(0, 200));

    // "мҳӨлҘҳ м—ҶмқҢ" мқ‘лӢө мІҳлҰ¬
    if (aiResponse.includes("мҳӨлҘҳ м—ҶмқҢ") || aiResponse.includes("мҳӨлҘҳк°Җ м—Ҷ")) {
      console.log("вң… л§һм¶ӨлІ• кІҖмӮ¬ мҷ„лЈҢ: мҳӨлҘҳ м—ҶмқҢ");
      return res.json({
        errata_count: 0,
        origin_html: text,
        html: text,
        notag_html: text
      });
    }

    // JSON мқ‘лӢө нҢҢмӢұ
    const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const result = JSON.parse(jsonMatch[0]);

      if (result.has_errors && result.errors && result.errors.length > 0) {
        let htmlText = text;
        let correctedHtml = result.corrected_text || text;

        // мҳӨлҘҳ л¶Җл¶„м—җ л№Ёк°„ л°‘мӨ„ м¶”к°Җ
        result.errors.forEach(error => {
          const wrongText = error.wrong;
          htmlText = htmlText.replace(
            new RegExp(wrongText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
            `<span class="highlight-wrong">${wrongText}</span>`
          );

          // мҲҳм •лҗң н…ҚмҠӨнҠём—җ л…№мғү н•ҳмқҙлқјмқҙнҠё м¶”к°Җ
          const correctText = error.correct;
          correctedHtml = correctedHtml.replace(
            new RegExp(correctText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
            `<span class="highlight-correct">${correctText}</span>`
          );
        });

        console.log(`вң… л§һм¶ӨлІ• кІҖмӮ¬ мҷ„лЈҢ: ${result.errors.length}к°ң мҳӨлҘҳ л°ңкІ¬`);

        return res.json({
          errata_count: result.errors.length,
          origin_html: text,
          html: htmlText,
          notag_html: result.corrected_text || text,
          corrected_html: correctedHtml,
          errors: result.errors
        });
      }
    }

    // JSON нҢҢмӢұ мӢӨнҢЁ лҳҗлҠ” мҳӨлҘҳ м—ҶмқҢ
    console.log("вң… л§һм¶ӨлІ• кІҖмӮ¬ мҷ„лЈҢ: мҳӨлҘҳ м—ҶмқҢ");
    res.json({
      errata_count: 0,
      origin_html: text,
      html: text,
      notag_html: text
    });

  } catch (err) {
    console.error("вқҢ /api/spell-check м—җлҹ¬:", err.message);
    // м—җлҹ¬ мӢңм—җлҸ„ мӣҗліё н…ҚмҠӨнҠё л°ҳнҷҳ
    res.json({
      errata_count: 0,
      origin_html: text,
      html: text,
      notag_html: text
    });
  }
});

// вң… AI кёҖ лӢӨл“¬кё° API (л§һм¶ӨлІ• + л¬ёмһҘ к°ңм„ )
app.post("/api/polish-writing", async (req, res) => {
  console.log("вң… [POST] /api/polish-writing нҳём¶ң");

  const { text } = req.body;

  if (!text || text.trim().length === 0) {
    return res.status(400).json({ error: "н…ҚмҠӨнҠёлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”." });
  }

  try {
    const OpenAI = require('openai');
    const openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY
    });

    console.log("рҹӨ– OpenAI APIлЎң кёҖ лӢӨл“¬кё° мӢңмһ‘...");

    // OpenAI API нҳём¶ң
    const response = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: `лӢ№мӢ мқҖ мҙҲл“ұн•ҷмғқ~мӨ‘н•ҷмғқмқҳ кёҖм“°кё°лҘј лҸ„мҷҖмЈјлҠ” м№ңм Ҳн•ң AI кі лһҳмғҳмһ…лӢҲлӢӨ.
н•ҷмғқмқҙ мһ‘м„ұн•ң кёҖмқ„ лӢӨл“¬кі , лҚ” н’Қм„ұн•ҳкІҢ нҷ•мһҘн•ҙмЈјм„ёмҡ”. лӢӨмқҢ мӮ¬н•ӯмқ„ м§ҖмјңмЈјм„ёмҡ”:

1. л§һм¶ӨлІ•кіј лқ„м–ҙм“°кё° мҳӨлҘҳлҘј мҲҳм •н•©лӢҲлӢӨ
2. л¬ёмһҘмқҙ мһҗм—°мҠӨлҹҪкІҢ мқҪнһҲлҸ„лЎқ к°ңм„ н•©лӢҲлӢӨ
3. н•ҷмғқмқҳ мӣҗлһҳ мқҳлҸ„мҷҖ н‘ңнҳ„мқ„ мөңлҢҖн•ң мӮҙлҰҪлӢҲлӢӨ
4. л„Ҳл¬ҙ м–ҙл Өмҡҙ лӢЁм–ҙлҠ” н”јн•ҳкі  н•ҷмғқ мҲҳмӨҖм—җ л§һкІҢ мң м§Җн•©лӢҲлӢӨ
5. кёҖмқҳ кө¬мЎ°к°Җ л…јлҰ¬м ҒмңјлЎң нқҗлҘҙлҸ„лЎқ к°ңм„ н•©лӢҲлӢӨ
6. **мӨ‘мҡ”: н•ҷмғқмқҳ кёҖмқ„ лҚ” н’Қм„ұн•ҳкі  кө¬мІҙм ҒмңјлЎң нҷ•мһҘн•©лӢҲлӢӨ**
   - м§§мқҖ л¬ёмһҘмқҖ мқҙмң , мҳҲмӢң, к°җм •, кө¬мІҙм Ғ мғҒнҷ©мқ„ лҚ§л¶ҷм—¬ нҷ•мһҘн•©лӢҲлӢӨ
   - "~н•ҳкі  мӢ¶лӢӨ" вҶ’ "мҷң к·ёл ҮкІҢ н•ҳкі  мӢ¶мқҖм§Җ", "м–ҙл–»кІҢ н•  кІғмқём§Җ" л“ұмқ„ м¶”к°Җн•©лӢҲлӢӨ
   - лӢЁ, н•ҷмғқмқҳ мӣҗлһҳ мғқк°Ғмқ„ нҒ¬кІҢ лІ—м–ҙлӮҳм§Җ м•ҠлҸ„лЎқ мЈјмқҳн•©лӢҲлӢӨ
   - нҷ•мһҘлҗң кёҖмқҖ мӣҗлһҳ кёҖмқҳ 1.5~2л°° м •лҸ„ л¶„лҹүмқҙ лҗҳлҸ„лЎқ н•©лӢҲлӢӨ
7. **мӨ‘мҡ”: лӢӨл“¬м–ҙм§„ кёҖм—җм„ң мҲҳм •н•ҳкұ°лӮҳ м¶”к°Җн•ң л¶Җл¶„мқҖ л°ҳл“ңмӢң <mark></mark> нғңк·ёлЎң к°җмӢёмЈјм„ёмҡ”**
   - мҳҲ: "лӮҳлҠ” <mark>м •л§җ</mark> н–үліөн–Ҳм–ҙмҡ”" (м¶”к°Җлҗң лӢЁм–ҙ)
   - мҳҲ: "<mark>к·ёлһҳм„ң лҚ”мҡұ м—ҙмӢ¬нһҲ л…ёл Ҙн•ҳкё°лЎң л§ҲмқҢлЁ№м—ҲмҠөлӢҲлӢӨ.</mark>" (м¶”к°Җлҗң л¬ёмһҘ)

л°ҳл“ңмӢң лӢӨмқҢ JSON нҳ•мӢқмңјлЎңл§Ң мқ‘лӢөн•ҳм„ёмҡ”:
{
  "directions": [
    "кёҖмқ„ лӢӨл“¬мқҖ л°©н–Ҙ 1 (мҳҲ: л¬ёмһҘмқ„ лҚ” мһҗм—°мҠӨлҹҪкІҢ м—°кІ°н–Ҳм–ҙмҡ”)",
    "кёҖмқ„ лӢӨл“¬мқҖ л°©н–Ҙ 2 (мҳҲ: кө¬мІҙм Ғмқё мҳҲмӢңлҘј м¶”к°Җн–Ҳм–ҙмҡ”)",
    "кёҖмқ„ лӢӨл“¬мқҖ л°©н–Ҙ 3 (мҳҲ: к°җм •кіј мқҙмң лҘј лҚ” н’Қл¶Җн•ҳкІҢ н‘ңнҳ„н–Ҳм–ҙмҡ”)"
  ],
  "polished_text": "лӢӨл“¬м–ҙм§Җкі  нҷ•мһҘлҗң кёҖ (мҲҳм •/м¶”к°Җлҗң л¶Җл¶„мқҖ <mark></mark>лЎң к°җмӢёкё°)",
  "feedback": "directionsм—җм„ң м–ёкёүн•ң лӢӨл“¬мқҖ л°©н–Ҙмқ„ нҷңмҡ©н•ҳл©ҙ лҚ” мўӢмқҖ кёҖмқҙ лҗңлӢӨкі  кІ©л Өн•ҳл©°, лӢӨл“¬м–ҙм§„ кёҖмқ„ м°ёкі н•ҙм„ң лӢӨмӢң мҚЁліҙлқјкі  мқ‘мӣҗн•ҳлҠ” л©”мӢңм§Җ (мҳҲ: л¬ёмһҘ м—°кІ°кіј кө¬мІҙм Ғмқё мҳҲмӢңлҘј мһҳ нҷңмҡ©н•ҳл©ҙ лҚ” л©Ӣм§„ кёҖмқҙ лҗ  кұ°мҳҲмҡ”! лӢӨл“¬м–ҙм§„ кёҖмқ„ м°ёкі н•ҙм„ң лӮҳл§Ңмқҳ кёҖлЎң лӢӨмӢң мһ‘м„ұн•ҙліҙм„ёмҡ”!)"
}`
        },
        {
          role: "user",
          content: `лӢӨмқҢ кёҖмқ„ лӢӨл“¬м–ҙмЈјм„ёмҡ”:\n\n"${text}"`
        }
      ],
      temperature: 0.7,
      max_tokens: 2000
    });

    const aiResponse = response.choices[0].message.content.trim();
    console.log("рҹӨ– AI мқ‘лӢө:", aiResponse);

    // JSON нҢҢмӢұ мӢңлҸ„
    try {
      // JSON лё”лЎқ м¶”м¶ң
      let jsonStr = aiResponse;
      const jsonMatch = aiResponse.match(/```json\s*([\s\S]*?)\s*```/);
      if (jsonMatch) {
        jsonStr = jsonMatch[1];
      } else {
        // JSON к°қмІҙл§Ң м¶”м¶ң
        const jsonStart = aiResponse.indexOf('{');
        const jsonEnd = aiResponse.lastIndexOf('}');
        if (jsonStart !== -1 && jsonEnd !== -1) {
          jsonStr = aiResponse.substring(jsonStart, jsonEnd + 1);
        }
      }

      const result = JSON.parse(jsonStr);

      console.log("вң… кёҖ лӢӨл“¬кё° мҷ„лЈҢ");

      return res.json({
        success: true,
        original_text: text,
        directions: result.directions || [],
        polished_text: result.polished_text || text,
        feedback: result.feedback || "лӢӨмӢң н•ң лІҲ кёҖмқ„ мҷ„м„ұн•ҙліҙм„ёмҡ”!"
      });

    } catch (parseError) {
      console.log("JSON нҢҢмӢұ мӢӨнҢЁ, мӣҗліё мқ‘лӢө мӮ¬мҡ©:", parseError.message);

      // JSON нҢҢмӢұ мӢӨнҢЁмӢң к°„лӢЁн•ң мқ‘лӢө
      return res.json({
        success: true,
        original_text: text,
        directions: [],
        polished_text: text,
        feedback: "лӢӨмӢң н•ң лІҲ кёҖмқ„ мҷ„м„ұн•ҙліҙм„ёмҡ”!"
      });
    }

  } catch (err) {
    console.error("вқҢ /api/polish-writing м—җлҹ¬:", err.message);
    res.status(500).json({
      success: false,
      error: "AI мІҳлҰ¬ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.",
      original_text: text
    });
  }
});

