// ===== н•ҷмҠө кё°лЎқ мӮӯм ң (мҶҢн”„нҠё мӮӯм ң) =====
app.post("/admin/log/delete/:id", async (req, res) => {
  const { key } = req.query;
  const { id } = req.params;

  // мҠҲнҚјкҙҖлҰ¬мһҗ key лҳҗлҠ” лёҢлһңм№ҳ кҙҖлҰ¬мһҗ м„ём…ҳ мІҙнҒ¬
  const isSuperAdmin = key === ADMIN_KEY;
  const isBranchAdmin = req.session && req.session.admin;

  if (!isSuperAdmin && !isBranchAdmin) {
    return res.status(403).json({ success: false, message: "кҙҖлҰ¬мһҗ мқёмҰқ мӢӨнҢЁ" });
  }

  try {
    const result = await LearningLog.findByIdAndUpdate(
      id,
      { deleted: true },
      { new: true }
    );

    if (!result) {
      return res.status(404).json({ success: false, message: "кё°лЎқмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ" });
    }

    res.json({ success: true, message: "мӮӯм ңлҗҳм—ҲмҠөлӢҲлӢӨ" });
  } catch (err) {
    console.error("мӮӯм ң мҳӨлҘҳ:", err);
    res.status(500).json({ success: false, message: err.message });
  }
});

