// мӮ¬мҡ©мһҗ лҚ°мқҙн„° мЎ°нҡҢ
app.get('/api/user-progress', async (req, res) => {
  try {
    const { grade, name } = req.query;

    if (!grade || !name) {
      return res.status(400).json({
        ok: false,
        message: 'gradeмҷҖ name нҢҢлқјлҜён„°к°Җ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    // unitProgress м ңмҷён•ҳкі  н•„мҡ”н•ң н•„л“ңл§Ң мЎ°нҡҢ (м„ұлҠҘ мөңм Ғнҷ” - 1.3MB вҶ’ мҲҳKB)
    let progress = await UserProgress.findOne(
      { grade, name },
      { unitProgress: 0 }  // unitProgress м ңмҷё
    ).lean();

    // лҚ°мқҙн„°к°Җ м—Ҷмңјл©ҙ мҙҲкё° лҚ°мқҙн„° мғқм„ұ
    if (!progress) {
      const newProgress = new UserProgress({
        grade,
        name,
        vocabularyQuiz: {
          totalScore: 0,
          quizCount: 0,
          avgScore: 0,
          totalCoins: 0,
          usedCoins: 0,
          currentRank: 0,
          previousRank: 0
        },
        studyRoom: {
          assignedTasks: []
        }
      });
      await newProgress.save();
      progress = newProgress.toObject();
      delete progress.unitProgress;
    }

    res.json({
      ok: true,
      data: progress
    });
  } catch (error) {
    console.error('мӮ¬мҡ©мһҗ лҚ°мқҙн„° мЎ°нҡҢ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// рҹҗӢ кі лһҳ л°°м§Җ мЎ°нҡҢ API (к°„лӢЁ лІ„м „)
app.get('/api/user-progress/whale-badges', async (req, res) => {
  try {
    const { grade, name } = req.query;

    if (!grade || !name) {
      return res.status(400).json({
        ok: false,
        message: 'gradeмҷҖ nameмқҙ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    const progress = await UserProgress.findOne(
      { grade, name },
      { 'vocabularyQuiz.totalCoins': 1, 'vocabularyQuiz.usedCoins': 1 }
    ).lean();

    const totalCoins = progress?.vocabularyQuiz?.totalCoins || 0;
    const usedCoins = progress?.vocabularyQuiz?.usedCoins || 0;

    res.json({
      ok: true,
      totalCoins,
      usedCoins,
      availableCoins: totalCoins - usedCoins
    });
  } catch (error) {
    console.error('кі лһҳ л°°м§Җ мЎ°нҡҢ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ'
    });
  }
});

// м–ҙнңҳнҖҙмҰҲ лҚ°мқҙн„° м ҖмһҘ
app.post('/api/user-progress/vocabulary', async (req, res) => {
  try {
    const { grade, name, vocabularyData } = req.body;

    if (!grade || !name || !vocabularyData) {
      return res.status(400).json({
        ok: false,
        message: 'grade, name, vocabularyDataк°Җ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    let progress = await UserProgress.findOne({ grade, name });

    if (!progress) {
      progress = new UserProgress({ grade, name });
    }

    // м–ҙнңҳнҖҙмҰҲ лҚ°мқҙн„° м—…лҚ°мқҙнҠё
    progress.vocabularyQuiz = {
      ...progress.vocabularyQuiz.toObject(),
      ...vocabularyData,
      lastRankUpdate: vocabularyData.lastRankUpdate || progress.vocabularyQuiz.lastRankUpdate
    };

    await progress.save();

    res.json({
      ok: true,
      message: 'м–ҙнңҳнҖҙмҰҲ лҚ°мқҙн„°к°Җ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ',
      data: progress
    });
  } catch (error) {
    console.error('м–ҙнңҳнҖҙмҰҲ лҚ°мқҙн„° м ҖмһҘ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// м–ҙнңҳн•ҷмҠө мқҙл Ҙ м ҖмһҘ API
app.post('/api/user-progress/vocabulary-history/add', async (req, res) => {
  try {
    const { grade, name, historyData } = req.body;

    if (!grade || !name || !historyData) {
      return res.status(400).json({
        ok: false,
        message: 'grade, name, historyDataк°Җ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    const { vocabCount, correctAnswers, totalQuestions, score, questions } = historyData;

    if (!vocabCount || correctAnswers === undefined || !totalQuestions || score === undefined) {
      return res.status(400).json({
        ok: false,
        message: 'м–ҙнңҳн•ҷмҠө мқҙл Ҙ лҚ°мқҙн„°к°Җ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ'
      });
    }

    let progress = await UserProgress.findOne({ grade, name });

    if (!progress) {
      progress = new UserProgress({ grade, name });
    }

    // мқҙл Ҙ м¶”к°Җ (мөңмӢ мҲңмңјлЎң мң м§Җн•ҳкё° мң„н•ҙ л°°м—ҙ м•һм—җ м¶”к°Җ)
    progress.vocabularyQuizHistory.unshift({
      date: new Date(),
      vocabCount,
      correctAnswers,
      totalQuestions,
      score,
      questions: questions || [] // л¬ём ңлі„ мғҒм„ё кІ°кіј
    });

    await progress.save();

    res.json({
      ok: true,
      message: 'м–ҙнңҳн•ҷмҠө мқҙл Ҙмқҙ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ',
      data: progress.vocabularyQuizHistory
    });
  } catch (error) {
    console.error('м–ҙнңҳн•ҷмҠө мқҙл Ҙ м ҖмһҘ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// м–ҙнңҳн•ҷмҠө мқҙл Ҙ мЎ°нҡҢ API
app.get('/api/user-progress/vocabulary-history', async (req, res) => {
  try {
    const { grade, name, offset = 0, limit = 10 } = req.query;

    if (!grade || !name) {
      return res.status(400).json({
        ok: false,
        message: 'gradeмҷҖ nameмқҙ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    const progress = await UserProgress.findOne({ grade, name });

    if (!progress) {
      return res.json({
        ok: true,
        history: [],
        total: 0,
        hasMore: false
      });
    }

    const offsetNum = parseInt(offset) || 0;
    const limitNum = parseInt(limit) || 10;

    // мқҙлҜё мөңмӢ мҲңмңјлЎң м ҖмһҘлҗҳм–ҙ мһҲмқҢ
    const history = progress.vocabularyQuizHistory || [];
    const total = history.length;
    const slicedHistory = history.slice(offsetNum, offsetNum + limitNum);
    const hasMore = (offsetNum + limitNum) < total;

    res.json({
      ok: true,
      history: slicedHistory,
      total,
      hasMore
    });
  } catch (error) {
    console.error('м–ҙнңҳн•ҷмҠө мқҙл Ҙ мЎ°нҡҢ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// мҳӨлҠҳ лӮ м§ң м–ҙнңҳнҖҙмҰҲ мҷ„лЈҢ м—¬л¶Җ нҷ•мқё API
app.get('/api/user-progress/vocabulary-history/today', async (req, res) => {
  try {
    const { grade, name } = req.query;

    if (!grade || !name) {
      return res.status(400).json({
        ok: false,
        message: 'gradeмҷҖ nameмқҙ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    // вң… мәҗмӢң нҷ•мқё (10мҙҲ мәҗмӢң - м–ҙнңҳн•ҷмҠө мҷ„лЈҢ м—¬л¶ҖлҠ” мһҗмЈј ліҖкІҪлҗ  мҲҳ мһҲмқҢ)
    const cacheKey = getCacheKey('vocab-today', { grade, name });
    const cached = getCache(cacheKey);
    if (cached) {
      return res.json(cached);
    }

    const progress = await UserProgress.findOne({ grade, name }).lean();

    if (!progress || !progress.vocabularyQuizHistory || progress.vocabularyQuizHistory.length === 0) {
      const result = { ok: true, completedToday: false };
      setCache(cacheKey, result);
      return res.json(result);
    }

    // мҳӨлҠҳ лӮ м§ң лІ”мң„ кі„мӮ° (KST кё°мӨҖ 00:00:00 ~ 23:59:59)
    const now = new Date();
    const kstOffset = 9 * 60 * 60 * 1000;
    const kstNow = new Date(now.getTime() + kstOffset);
    const kstTodayStart = new Date(Date.UTC(kstNow.getUTCFullYear(), kstNow.getUTCMonth(), kstNow.getUTCDate(), 0, 0, 0) - kstOffset);
    const kstTodayEnd = new Date(Date.UTC(kstNow.getUTCFullYear(), kstNow.getUTCMonth(), kstNow.getUTCDate(), 23, 59, 59) - kstOffset);

    const todayHistory = progress.vocabularyQuizHistory.find(history => {
      const historyDate = new Date(history.date);
      return historyDate >= kstTodayStart && historyDate <= kstTodayEnd;
    });

    const result = {
      ok: true,
      completedToday: !!todayHistory,
      latestHistory: todayHistory || null
    };

    // вң… мәҗмӢң м ҖмһҘ
    setCache(cacheKey, result);

    res.json(result);
  } catch (error) {
    console.error('мҳӨлҠҳ м–ҙнңҳн•ҷмҠө мқҙл Ҙ нҷ•мқё мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

