// лҸ…м„ң к°җмғҒл¬ё м ңм¶ң
app.post('/api/user-progress/reading-reports/submit', async (req, res) => {
  try {
    const { grade, name, title, content, type, storyId, storyTitle } = req.body;

    if (!grade || !name || !title || !content || !type) {
      return res.status(400).json({
        ok: false,
        message: 'лӘЁл“  н•„л“ңк°Җ н•„мҡ”н•©лӢҲлӢӨ'
      });
    }

    // нҳ„мһ¬ мӣ” кі„мӮ°
    const now = new Date();
    const month = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

    let progress = await UserProgress.findOne({ grade, name });

    if (!progress) {
      progress = new UserProgress({
        grade,
        name,
        readingReports: []
      });
    }

    if (!progress.readingReports) {
      progress.readingReports = [];
    }

    // мғҲлЎңмҡҙ лҰ¬нҸ¬нҠё м¶”к°Җ
    progress.readingReports.push({
      title,
      content,
      type,
      storyId: storyId || 'whale_island',
      storyTitle: storyTitle || 'н‘ёлҘё кі лһҳм„¬мқҳ л№„л°Җ лӘЁн—ҳлӢЁ мӢңмҰҢ 1: н‘ёлҘё кі лһҳм„¬ нғҗн—ҳ',
      submittedAt: new Date(),
      month
    });

    await progress.save();

    res.json({
      ok: true,
      message: 'лҸ…м„ң к°җмғҒл¬ёмқҙ м ңм¶ңлҗҳм—ҲмҠөлӢҲлӢӨ',
      reportId: progress.readingReports[progress.readingReports.length - 1]._id
    });
  } catch (error) {
    console.error('лҸ…м„ң к°җмғҒл¬ё м ңм¶ң мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳ',
      error: error.message
    });
  }
});

