// ===== Multer м„Өм • (мқҙлҜём§Җ м—…лЎңл“ңмҡ©) =====
// мһ„мӢң мқҙлҜём§Җ м ҖмһҘмқ„ мң„н•ң л””л үнҶ лҰ¬ мғқм„ұ
const tempUploadsDir = path.join(__dirname, 'public', 'temp-uploads');
if (!fs.existsSync(tempUploadsDir)) {
  fs.mkdirSync(tempUploadsDir, { recursive: true });
}

const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, tempUploadsDir);
  },
  filename: function (req, file, cb) {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    cb(null, 'reading-report-' + uniqueSuffix + path.extname(file.originalname));
  }
});

const upload = multer({
  storage: storage,
  limits: { fileSize: 10 * 1024 * 1024 }, // 10MB м ңн•ң
  fileFilter: function (req, file, cb) {
    const allowedTypes = /jpeg|jpg|png/;
    const extname = allowedTypes.test(path.extname(file.originalname).toLowerCase());
    const mimetype = allowedTypes.test(file.mimetype);

    if (mimetype && extname) {
      return cb(null, true);
    } else {
      cb(new Error('мқҙлҜём§Җ нҢҢмқјл§Ң м—…лЎңл“ң к°ҖлҠҘн•©лӢҲлӢӨ (jpeg, jpg, png)'));
    }
  }
});

// мһ„мӢң мқҙлҜём§Җ м—…лЎңл“ң API
app.post('/api/upload-temp-image', upload.single('image'), (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({
        ok: false,
        message: 'мқҙлҜём§Җ нҢҢмқјмқҙ м—ҶмҠөлӢҲлӢӨ'
      });
    }

    // кіөк°ң URL мғқм„ұ
    const imageUrl = `${req.protocol}://${req.get('host')}/temp-uploads/${req.file.filename}`;

    console.log('рҹ“Ө мһ„мӢң мқҙлҜём§Җ м—…лЎңл“ң м„ұкіө:', imageUrl);

    // 1мӢңк°„ нӣ„ мһҗлҸҷ мӮӯм ң мҠӨмјҖмӨ„
    setTimeout(() => {
      fs.unlink(req.file.path, (err) => {
        if (err) {
          console.error('мһ„мӢң мқҙлҜём§Җ мӮӯм ң мӢӨнҢЁ:', err);
        } else {
          console.log('вң… мһ„мӢң мқҙлҜём§Җ мһҗлҸҷ мӮӯм ң:', req.file.filename);
        }
      });
    }, 60 * 60 * 1000); // 1мӢңк°„

    res.json({
      ok: true,
      imageUrl: imageUrl,
      filename: req.file.filename
    });
  } catch (error) {
    console.error('мқҙлҜём§Җ м—…лЎңл“ң мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'мқҙлҜём§Җ м—…лЎңл“ң мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// лҸ…м„ң к°җмғҒл¬ё кіөмң мҡ© ID мғқм„ұ л°Ҹ м ҖмһҘ
app.post('/api/reading-report/share', async (req, res) => {
  try {
    const { grade, name, title, content, storyId, storyTitle } = req.body;

    if (!grade || !name || !title || !content) {
      return res.status(400).json({
        ok: false,
        message: 'н•„мҲҳ м •ліҙк°Җ лҲ„лқҪлҗҳм—ҲмҠөлӢҲлӢӨ'
      });
    }

    // кі мң  кіөмң  ID мғқм„ұ (м§§мқҖ н•ҙмӢң)
    const crypto = require('crypto');
    const shareId = crypto.randomBytes(8).toString('hex');

    let progress = await UserProgress.findOne({ grade, name });

    if (!progress) {
      progress = new UserProgress({
        grade,
        name,
        sharedReports: []
      });
    }

    if (!progress.sharedReports) {
      progress.sharedReports = [];
    }

    // кіөмң мҡ© лҰ¬нҸ¬нҠё м ҖмһҘ
    progress.sharedReports.push({
      shareId,
      title,
      content,
      storyId: storyId || 'whale_island',
      storyTitle: storyTitle || '',
      sharedAt: new Date(),
      expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000) // 30мқј нӣ„ л§ҢлЈҢ
    });

    await progress.save();

    const host = req.get('host');
    const isProduction = host.includes('onrender.com') || host.includes('brainmoon.kr');
    const baseUrl = isProduction ? 'https://brainmoon.kr' : `http://${host}`;
    const shareUrl = `${baseUrl}/reading-report/view/${shareId}`;

    res.json({
      ok: true,
      shareId,
      shareUrl
    });
  } catch (error) {
    console.error('лҸ…м„ң к°җмғҒл¬ё кіөмң  ID мғқм„ұ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳ',
      error: error.message
    });
  }
});

// кіөмң лҗң лҸ…м„ң к°җмғҒл¬ё мЎ°нҡҢ
app.get('/api/reading-report/shared/:shareId', async (req, res) => {
  try {
    const { shareId } = req.params;

    // лӘЁл“  мӮ¬мҡ©мһҗм—җм„ң н•ҙлӢ№ shareId м°ҫкё°
    const progress = await UserProgress.findOne({
      'sharedReports.shareId': shareId
    });

    if (!progress) {
      return res.status(404).json({
        ok: false,
        message: 'кіөмң лҗң к°җмғҒл¬ёмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ'
      });
    }

    const report = progress.sharedReports.find(r => r.shareId === shareId);

    if (!report) {
      return res.status(404).json({
        ok: false,
        message: 'кіөмң лҗң к°җмғҒл¬ёмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ'
      });
    }

    // л§ҢлЈҢ нҷ•мқё
    if (report.expiresAt && new Date() > new Date(report.expiresAt)) {
      return res.status(410).json({
        ok: false,
        message: 'кіөмң  л§ҒнҒ¬к°Җ л§ҢлЈҢлҗҳм—ҲмҠөлӢҲлӢӨ'
      });
    }

    res.json({
      ok: true,
      report: {
        title: report.title,
        content: report.content,
        storyId: report.storyId,
        storyTitle: report.storyTitle,
        sharedAt: report.sharedAt,
        authorGrade: progress.grade,
        authorName: progress.name
      }
    });
  } catch (error) {
    console.error('кіөмң лҗң к°җмғҒл¬ё мЎ°нҡҢ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳ',
      error: error.message
    });
  }
});

// кіөмң лҗң лҸ…м„ң к°җмғҒл¬ё нҺҳмқҙм§Җ лқјмҡ°нҢ… - menu.htmlлЎң лҰ¬лӢӨмқҙл үнҠён•ҳм—¬ нҢқм—… н‘ңмӢң
