/* ====================================
 * вң… мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • API
 * ==================================== */

// мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • мҠӨнӮӨл§Ҳ
const autoTaskSettingsSchema = new mongoose.Schema({
  grade: { type: String, required: true },
  name: { type: String, required: true },
  series: [{ type: String }],        // м„ нғқлҗң мӢңлҰ¬мҰҲ ('up', 'fit')
  days: [{ type: String }],          // м„ нғқлҗң мҡ”мқј (0~6, 'everyday')
  domains: [{ type: String }], // м„ нғқлҗң л¶„м•ј л°°м—ҙ (['all'], ['science', 'social'], etc.)
  taskCount: { type: Number, default: 3 }, // кіјм ң к°ңмҲҳ
  status: { type: String, enum: ['running', 'paused', 'stopped'], default: 'stopped' },
  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now }
});
autoTaskSettingsSchema.index({ grade: 1, name: 1 }, { unique: true });
const AutoTaskSettings = mongoose.model('AutoTaskSettings', autoTaskSettingsSchema);

// мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • мЎ°нҡҢ
app.get('/api/auto-task-settings', async (req, res) => {
  try {
    const { grade, name } = req.query;
    if (!grade || !name) {
      return res.status(400).json({ ok: false, message: 'grade, nameмқҙ н•„мҡ”н•©лӢҲлӢӨ' });
    }

    const settings = await AutoTaskSettings.findOne({ grade, name });
    res.json({ ok: true, settings: settings || null });
  } catch (error) {
    console.error('мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • мЎ°нҡҢ мҳӨлҘҳ:', error);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ' });
  }
});

// мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • м ҖмһҘ
app.post('/api/auto-task-settings', async (req, res) => {
  try {
    const { grade, name, settings } = req.body;
    if (!grade || !name || !settings) {
      return res.status(400).json({ ok: false, message: 'grade, name, settingsк°Җ н•„мҡ”н•©лӢҲлӢӨ' });
    }

    // кё°мЎҙ м„Өм • мЎ°нҡҢ (м„Өм • ліҖкІҪ м—¬л¶Җ нҷ•мқёмҡ©)
    const existingSettings = await AutoTaskSettings.findOne({ grade, name });

    // м„Өм •мқҙ ліҖкІҪлҗҳм—ҲлҠ”м§Җ нҷ•мқё (мӢңлҰ¬мҰҲ, мҡ”мқј, к°ңмҲҳ ліҖкІҪ мӢң)
    const settingsChanged = existingSettings && (
      JSON.stringify(existingSettings.series?.sort()) !== JSON.stringify(settings.series?.sort()) ||
      JSON.stringify(existingSettings.days?.sort()) !== JSON.stringify(settings.days?.sort()) ||
      existingSettings.taskCount !== settings.taskCount
    );

    // м„Өм •мқҙ ліҖкІҪлҗҳм—Ҳмңјл©ҙ кё°мЎҙ мһҗлҸҷл¶Җм—¬ кіјм ң мӮӯм ң
    if (settingsChanged || settings.status === 'running') {
      console.log(`рҹ—‘пёҸ [${grade} ${name}] мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • ліҖкІҪ - кё°мЎҙ мһҗлҸҷл¶Җм—¬ кіјм ң мӮӯм ң`);

      // н•ҷмҠөмӢӨм—җм„ң isAutoAssigned === trueмқё кіјм ңл§Ң мӮӯм ң (мқјл°ҳ кіјм ңлҠ” мң м§Җ)
      const userProgress = await UserProgress.findOne({ grade, name });
      if (userProgress?.studyRoom?.assignedTasks) {
        const manualTasks = userProgress.studyRoom.assignedTasks.filter(task => !task.isAutoAssigned);
        const deletedCount = userProgress.studyRoom.assignedTasks.length - manualTasks.length;

        await UserProgress.updateOne(
          { grade, name },
          { $set: { 'studyRoom.assignedTasks': manualTasks } }
        );

        console.log(`  вң… ${deletedCount}к°ң мһҗлҸҷл¶Җм—¬ кіјм ң мӮӯм ң мҷ„лЈҢ`);
      }
    }

    const updatedSettings = await AutoTaskSettings.findOneAndUpdate(
      { grade, name },
      {
        ...settings,
        grade,
        name,
        updatedAt: new Date()
      },
      { upsert: true, new: true }
    );

    // "мӢңмһ‘" мғҒнғңмқҙл©ҙ л°”лЎң мһҗлҸҷкіјм ңл¶Җм—¬ мӢӨн–ү
    if (settings.status === 'running') {
      console.log(`в–¶пёҸ [${grade} ${name}] мһҗлҸҷкіјм ңл¶Җм—¬ мҰүмӢң мӢӨн–ү`);
      // л№„лҸҷкё°лЎң мһҗлҸҷкіјм ң л¶Җм—¬ мӢӨн–ү (мқ‘лӢөмқҖ лЁјм Җ ліҙлғ„)
      executeAutoTaskForStudent(grade, name, updatedSettings).catch(err => {
        console.error(`вқҢ [${grade} ${name}] мһҗлҸҷкіјм ңл¶Җм—¬ мӢӨн–ү мҳӨлҘҳ:`, err);
      });
    }

    res.json({ ok: true, settings: updatedSettings });
  } catch (error) {
    console.error('мһҗлҸҷкіјм ңл¶Җм—¬ м„Өм • м ҖмһҘ мҳӨлҘҳ:', error);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ' });
  }
});

/* ====================================
 * вң… AI мһҗлҸҷ кіјм ң л¶Җм—¬ мӢңмҠӨн…ң
 * ==================================== */

// AI кіјм ң мҠӨмјҖмӨ„ мҠӨнӮӨл§Ҳ
const aiTaskScheduleSchema = new mongoose.Schema({
  studentGrade: { type: String, required: true },
  studentName: { type: String, required: true },
  unitId: { type: String, required: true },
  unitTitle: { type: String, required: true },
  seriesName: { type: String, required: true },
  fieldName: { type: String, required: true },
  subjectName: { type: String, required: true },
  grade: { type: String, required: true }, // л“ұкёү: excellent, good, average, encourage
  gradeText: { type: String, required: true }, // л“ұкёү н…ҚмҠӨнҠё: мҡ°мҲҳ, м–‘нҳё, ліҙнҶө, кІ©л Ө
  avgScore: { type: Number, required: true }, // нҸүк·  м җмҲҳ
  completedAt: { type: Date, required: true }, // н•ҷмҠө мҷ„лЈҢ лӮ м§ң
  scheduledDate: { type: Date, required: true }, // л¶Җм—¬ мҳҲм • лӮ м§ң
  assignedAt: { type: Date }, // мӢӨм ң л¶Җм—¬лҗң лӮ м§ң
  status: {
    type: String,
    enum: ['pending', 'assigned', 'completed'],
    default: 'pending'
  },
  createdAt: { type: Date, default: Date.now }
});

const AITaskSchedule = mongoose.model('AITaskSchedule', aiTaskScheduleSchema);

// л“ұкёү нҢҗм • н•ЁмҲҳ (menu.htmlкіј лҸҷмқјн•ң лЎңм§Ғ)
// AI м¶”мІңкіјм ң л¶Җм—¬ мӢңк°„ м„Өм •
function getGradeInfo(avgScore) {
  if (avgScore >= 9) {
    return { grade: 'excellent', text: 'мҡ°мҲҳ', hours: 0 }; // мҡ°мҲҳлҠ” л¶Җм—¬ м•Ҳ н•Ё
  } else if (avgScore >= 8) {
    return { grade: 'good', text: 'м–‘нҳё', hours: 336 }; // м–‘нҳё: 14мқј(336мӢңк°„) нӣ„
  } else if (avgScore >= 7) {
    return { grade: 'average', text: 'ліҙнҶө', hours: 168 }; // ліҙнҶө: 7мқј(168мӢңк°„) нӣ„
  } else {
    return { grade: 'encourage', text: 'кІ©л Ө', hours: 72 }; // кІ©л Ө: 3мқј(72мӢңк°„) нӣ„
  }
}

// [DEPRECATED] AI кіјм ң мҠӨмјҖмӨ„ мғқм„ұ/м—…лҚ°мқҙнҠё API
// мқҙм ң assignAITasksDaily()к°Җ LearningLog н…Ңмқҙлё”м—җм„ң м§Ғм ‘ лҚ°мқҙн„°лҘј мқҪм–ҙ кіјм ңлҘј л¶Җм—¬н•Ё
// нҒҙлқјмқҙм–ёнҠём—җм„ң лҚ” мқҙмғҒ мқҙ APIлҘј нҳём¶ңн•ҳм§Җ м•ҠмқҢ
app.post('/api/ai-task/create-schedule', async (req, res) => {
  try {
    const {
      studentGrade,
      studentName,
      unitId,
      unitTitle,
      seriesName,
      fieldName,
      subjectName,
      avgScore,
      completedAt
    } = req.body;

    // л“ұкёү нҢҗм •
    const gradeInfo = getGradeInfo(avgScore);

    // мҡ°мҲҳ л“ұкёүмқҖ мҠӨмјҖмӨ„ мғқм„ұ м•Ҳ н•Ё
    if (gradeInfo.grade === 'excellent') {
      return res.json({
        ok: true,
        message: 'мҡ°мҲҳ л“ұкёүмқҖ мһ¬н•ҷмҠөмқҙ н•„мҡ”н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ',
        schedule: null
      });
    }

    // л¶Җм—¬ мҳҲм • лӮ м§ң кі„мӮ° - нҳ„мһ¬ мӢңк°„ кё°мӨҖмңјлЎң кі„мӮ° (ліөмҠө мҷ„лЈҢ мӢңм җ = м§ҖкёҲ)
    const now = new Date();
    const scheduledDate = new Date(now);
    // л“ұкёүлі„ мқјм • м Ғмҡ©: кІ©л Ө 24мӢңк°„, ліҙнҶө 48мӢңк°„, м–‘нҳё 72мӢңк°„
    scheduledDate.setHours(scheduledDate.getHours() + gradeInfo.hours);

    // кё°мЎҙ мҠӨмјҖмӨ„ нҷ•мқё (к°ҷмқҖ н•ҷмғқ, к°ҷмқҖ лӢЁмӣҗ)
    let schedule = await AITaskSchedule.findOne({
      studentGrade,
      studentName,
      unitId,
      status: { $in: ['pending', 'assigned'] }
    });

    if (schedule) {
      // кё°мЎҙ мҠӨмјҖмӨ„ м—…лҚ°мқҙнҠё
      schedule.grade = gradeInfo.grade;
      schedule.gradeText = gradeInfo.text;
      schedule.avgScore = avgScore;
      schedule.completedAt = now;  // нҳ„мһ¬ мӢңк°„ (ліөмҠө мҷ„лЈҢ мӢңм җ)
      schedule.scheduledDate = scheduledDate;
      schedule.status = 'pending';
      schedule.assignedAt = null;
      await schedule.save();
    } else {
      // мғҲ мҠӨмјҖмӨ„ мғқм„ұ
      schedule = await AITaskSchedule.create({
        studentGrade,
        studentName,
        unitId,
        unitTitle,
        seriesName,
        fieldName,
        subjectName,
        grade: gradeInfo.grade,
        gradeText: gradeInfo.text,
        avgScore,
        completedAt: now,  // нҳ„мһ¬ мӢңк°„ (ліөмҠө мҷ„лЈҢ мӢңм җ)
        scheduledDate
      });
    }

    res.json({
      ok: true,
      message: 'AI кіјм ң мҠӨмјҖмӨ„мқҙ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ',
      schedule
    });

  } catch (error) {
    console.error('AI кіјм ң мҠӨмјҖмӨ„ мғқм„ұ мҳӨлҘҳ:', error);
    res.status(500).json({
      ok: false,
      message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ',
      error: error.message
    });
  }
});

// л§Өмқј мһҗм • мӢӨн–ү: AI кіјм ң мһҗлҸҷ л¶Җм—¬ (LearningLog н…Ңмқҙлё” кё°мӨҖ)
// - мөңмў…мҷ„лЈҢ мӢңк°„кіј мөңмў…л“ұкёүмқ„ кё°мӨҖмңјлЎң AI м¶”мІңкіјм ң л¶Җм—¬
// - кІ©л Ө: 24мӢңк°„ нӣ„, ліҙнҶө: 48мӢңк°„ нӣ„, м–‘нҳё: 72мӢңк°„ нӣ„, мҡ°мҲҳ: л¶Җм—¬ м•Ҳ н•Ё
// - мҳӨлӢө кё°л°ҳ: мӨ‘мӢ¬л¬ёлӢЁ мҳӨлӢө + л¬ём ң мҳӨлӢө >= 3нҡҢ вҶ’ 1мӢңк°„ нӣ„ мһ¬л¶Җм—¬
// - мҷ„лЈҢлҗң AI кіјм ңлҠ” 24мӢңк°„ нӣ„ мһҗлҸҷ мӮӯм ң
async function assignAITasksDaily() {
  try {
    console.log('рҹӨ– [NEW] AI мһҗлҸҷ кіјм ң л¶Җм—¬ мӢңмһ‘ (LearningLog кё°мӨҖ):', new Date().toISOString());

    const now = new Date();

    // ========== мҷ„лЈҢлҗң AI м¶”мІңкіјм ң 24мӢңк°„ нӣ„ мһҗлҸҷ мӮӯм ң ==========
    console.log('рҹ—‘пёҸ мҷ„лЈҢлҗң AI м¶”мІңкіјм ң м •лҰ¬ мӢңмһ‘...');
    const AI_TASK_EXPIRE_HOURS = 24;

    const allProgress = await UserProgress.find({ 'studyRoom.assignedTasks': { $exists: true, $ne: [] } });
    let totalRemovedCount = 0;

    for (const progress of allProgress) {
      const tasks = progress.studyRoom?.assignedTasks || [];
      const originalLength = tasks.length;

      // мҷ„лЈҢлҗң AI кіјм ң мӨ‘ 24мӢңк°„ м§ҖлӮң кІғ н•„н„°л§Ғ
      const filteredTasks = tasks.filter(task => {
        // AI кіјм ңк°Җ м•„лӢҲл©ҙ мң м§Җ
        if (!task.isAI) return true;

        // мҷ„лЈҢлҗҳм§Җ м•ҠмқҖ кіјм ңлҠ” мң м§Җ
        if (task.status !== 'completed') return true;

        // completedAtмқҙ м—Ҷмңјл©ҙ мң м§Җ
        if (!task.completedAt) return true;

        // мҷ„лЈҢ нӣ„ 24мӢңк°„ кІҪкіј нҷ•мқё
        const completedAt = new Date(task.completedAt);
        const expireAt = new Date(completedAt.getTime() + AI_TASK_EXPIRE_HOURS * 60 * 60 * 1000);

        if (now >= expireAt) {
          console.log(`рҹ—‘пёҸ [${progress.name}] ${task.title || task.id} мӮӯм ң (мҷ„лЈҢ нӣ„ 24мӢңк°„ кІҪкіј)`);
          return false; // мӮӯм ң
        }

        return true; // мң м§Җ
      });

      const removedCount = originalLength - filteredTasks.length;
      if (removedCount > 0) {
        progress.studyRoom.assignedTasks = filteredTasks;
        await progress.save();
        totalRemovedCount += removedCount;
        console.log(`вң… [${progress.name}] ${removedCount}к°ң AI кіјм ң мӮӯм ң мҷ„лЈҢ`);
      }
    }

    console.log(`рҹ—‘пёҸ мҷ„лЈҢлҗң AI м¶”мІңкіјм ң м •лҰ¬ мҷ„лЈҢ: мҙқ ${totalRemovedCount}к°ң мӮӯм ң`);

    // ========== л“ұкёү кё°л°ҳ AI м¶”мІңкіјм ң л¶Җм—¬ ==========
    // лӘЁл“  LearningLog мЎ°нҡҢ (completedлҗң кІғл§Ң)
    const allLogs = await LearningLog.find({ completed: true, deleted: { $ne: true } });
    console.log(`рҹ“ҡ мЎ°нҡҢлҗң н•ҷмҠө лЎңк·ё мҲҳ: ${allLogs.length}к°ң`);

    // н•ҷмғқлі„лЎң к·ёлЈ№нҷ” (grade + name мЎ°н•©)
    const studentLogsMap = {};
    for (const log of allLogs) {
      const studentKey = `${log.grade}::${log.name}`;
      if (!studentLogsMap[studentKey]) {
        studentLogsMap[studentKey] = {
          grade: log.grade,
          name: log.name,
          logs: []
        };
      }
      studentLogsMap[studentKey].logs.push(log);
    }

    const studentKeys = Object.keys(studentLogsMap);
    console.log(`рҹ‘Ҙ мІҳлҰ¬н•  н•ҷмғқ мҲҳ: ${studentKeys.length}лӘ…`);

    for (const studentKey of studentKeys) {
      const studentData = studentLogsMap[studentKey];
      const { grade, name, logs } = studentData;

      if (!logs || logs.length === 0) continue;

      // лӢЁмӣҗлі„лЎң мөңмӢ  кё°лЎқл§Ң м¶”м¶ң (мөңмў…мҷ„лЈҢ мӢңк°„ = timestamp or aiReviewCompletedAt мӨ‘ мөңмӢ )
      const unitLatestLogs = {};

      for (const log of logs) {
        let unitId = log.unit;
        if (!unitId || !log.radar) continue;

        // рҹ”§ unit мҪ”л“ң м •к·ңнҷ”: world2_XX вҶ’ world_4X
        // LearningLogм—җ world2_01 к°ҷмқҖ мҪ”л“ңк°Җ м ҖмһҘлҗҳм–ҙ мһҲм§Җл§Ң, мӢӨм ң нҢҢмқјмқҖ world_41.html
        // (мқёл¬јмқҖ people2_XX.html нҢҢмқјмқҙ мӢӨм ңлЎң мЎҙмһ¬н•ҳлҜҖлЎң ліҖнҷҳн•ҳм§Җ м•ҠмқҢ)
        if (unitId.startsWith('world2_')) {
          const num = parseInt(unitId.replace('world2_', ''), 10);
          unitId = `world_${num + 40}`;
          console.log(`рҹ”„ [${name}] мҪ”л“ң ліҖнҷҳ: ${log.unit} вҶ’ ${unitId}`);
        }

        // мөңмў…мҷ„лЈҢ мӢңк°„ = н•ҷмҠө мҷ„лЈҢ мӢңк°„ (timestamp) кё°мӨҖмңјлЎңл§Ң кі„мӮ°
        // н•ҷмҠө кё°лЎқ лӘ©лЎқм—җм„ң ліҙм—¬мЈјлҠ” мҳҲм • мӢңк°„кіј лҸҷмқјн•ҳкІҢ м Ғмҡ©
        const finalCompletedAt = log.timestamp ? new Date(log.timestamp) : new Date(0);

        // нҸүк·  м җмҲҳ кі„мӮ°
        const scores = [
          log.radar.literal || 0,
          log.radar.structural || 0,
          log.radar.lexical || 0,
          log.radar.inferential || 0,
          log.radar.critical || 0
        ];
        const avgScore = scores.reduce((a, b) => a + b, 0) / 5;

        // лӢЁмӣҗлі„ мөңмӢ  кё°лЎқл§Ң мң м§Җ (timestamp кё°мӨҖ)
        const existingEntry = unitLatestLogs[unitId];
        if (!existingEntry || finalCompletedAt.getTime() > existingEntry.finalCompletedAt.getTime()) {
          unitLatestLogs[unitId] = {
            unitId,
            originalUnit: log.unit, // мӣҗліё unit мҪ”л“ң ліҙмЎҙ (title мғқм„ұмҡ©)
            avgScore,
            finalCompletedAt,
            series: log.series
          };
        }
      }

      // UserProgress мЎ°нҡҢ
      let progress = await UserProgress.findOne({ grade, name });
      if (!progress) {
        progress = new UserProgress({
          grade,
          name,
          studyRoom: { assignedTasks: [] }
        });
      }

      // кё°мЎҙ н•ҷмҠөмӢӨ кіјм ң лӘ©лЎқ
      const existingTasks = progress.studyRoom?.assignedTasks || [];
      // AI м¶”мІңкіјм ңл§Ң м¶”м¶ң (isAI: trueмқё кІғл§Ң мҠӨнӮө лҢҖмғҒ)
      const existingAIUnitIds = new Set(existingTasks.filter(t => t.isAI === true).map(t => {
        const taskId = t.unitId || t.id;
        // ./BRAINUP/xxx/yyy.html нҳ•мӢқм—җм„ң unit мҪ”л“ң м¶”м¶ң
        const match = taskId.match(/([a-z]+\d*_\d+)\.html$/i);
        if (match) return match[1];
        // мқҙлҜё unit мҪ”л“ң нҳ•мӢқмқҙл©ҙ к·ёлҢҖлЎң л°ҳнҷҳ
        return taskId;
      }));

      let assignedCount = 0;

      // л””лІ„к·ё: кё°мЎҙ н•ҷмҠөмӢӨ AI кіјм ң ID м¶ңл Ҙ
      console.log(`рҹ”Қ [${name}] кё°мЎҙ н•ҷмҠөмӢӨ AI кіјм ң IDs:`, Array.from(existingAIUnitIds));

      // к°Ғ лӢЁмӣҗмқҳ мөңмў…л“ұкёүкіј мөңмў…мҷ„лЈҢ мӢңк°„ нҷ•мқё
      for (const unitId in unitLatestLogs) {
        const unitInfo = unitLatestLogs[unitId];
        const { avgScore, finalCompletedAt, series } = unitInfo;

        // л“ұкёү нҢҗм •
        const gradeInfo = getGradeInfo(avgScore);

        // мҡ°мҲҳ л“ұкёүмқҖ AI кіјм ң л¶Җм—¬ м•Ҳ н•Ё
        if (gradeInfo.grade === 'excellent') {
          console.log(`вҸӯпёҸ [${name}] ${unitId}: мҡ°мҲҳ л“ұкёү вҶ’ мҠӨнӮө`);
          continue;
        }

        // мқҙлҜё AI м¶”мІңкіјм ңлЎң н•ҷмҠөмӢӨм—җ мһҲмңјл©ҙ мҠӨнӮө (мқјл°ҳкіјм ңлҠ” мҠӨнӮө м•Ҳн•Ё)
        if (existingAIUnitIds.has(unitId)) {
          console.log(`вҸӯпёҸ [${name}] ${unitId}: мқҙлҜё AI м¶”мІңкіјм ңлЎң мһҲмқҢ вҶ’ мҠӨнӮө`);
          continue;
        }

        // л“ұкёүлі„ лҢҖкё° мӢңк°„ кі„мӮ°
        const waitHours = gradeInfo.hours;
        const assignableAt = new Date(finalCompletedAt.getTime() + waitHours * 60 * 60 * 1000);

        // нҳ„мһ¬ мӢңк°„мқҙ л¶Җм—¬ к°ҖлҠҘ мӢңк°„мқ„ м§ҖлӮ¬лҠ”м§Җ нҷ•мқё
        console.log(`рҹ•җ [${name}] ${unitId}: л“ұкёү=${gradeInfo.text}, лҢҖкё°=${waitHours}мӢңк°„, л¶Җм—¬к°ҖлҠҘмӢңк°„=${assignableAt.toISOString()}, нҳ„мһ¬=${now.toISOString()}`);
        if (now >= assignableAt) {
          // лӢЁмӣҗ м •ліҙ м¶”м¶ң (мӣҗліё unit мҪ”л“ңм—җм„ң нҢҢмӢұ - title мғқм„ұмҡ©)
          const originalUnit = unitInfo.originalUnit || unitId;
          const parts = originalUnit.split('_');
          const subjectCode = parts[0];
          const unitNumber = parts[1] ? parseInt(parts[1], 10) : 1;

          // кіјлӘ©лӘ… л§Өн•‘ (world1, world2лҘј кө¬л¶„н•ҳм—¬ м„ёкі„л¬ён•ҷ1, м„ёкі„л¬ён•ҷ2лЎң н‘ңмӢң)
          const subjectMap = {
            'geo': 'м§ҖлҰ¬', 'bio': 'мғқл¬ј', 'earth': 'м§Җкө¬кіјн•ҷ', 'physics': 'л¬јлҰ¬', 'chem': 'нҷ”н•ҷ',
            'soc': 'мӮ¬нҡҢл¬ёнҷ”', 'law': 'лІ•', 'pol': 'м •м№ҳкІҪм ң',
            'modern': 'нҳ„лҢҖл¬ён•ҷ', 'classic': 'кі м „л¬ён•ҷ',
            'world1': 'м„ёкі„л¬ён•ҷ1', 'world2': 'м„ёкі„л¬ён•ҷ2', 'world': 'м„ёкі„л¬ён•ҷ1',
            'person1': 'н•ңкөӯмқёл¬ј', 'person2': 'м„ёкі„мқёл¬ј', 'people': 'н•ңкөӯмқёл¬ј',
            'people1': 'н•ңкөӯмқёл¬ј', 'people2': 'м„ёкі„мқёл¬ј'
          };
          const subjectName = subjectMap[subjectCode] || subjectCode;

          // л¶„м•јлӘ… л§Өн•‘
          const fieldMap = {
            'geo': 'мӮ¬нҡҢ', 'soc': 'мӮ¬нҡҢ', 'law': 'мӮ¬нҡҢ', 'pol': 'мӮ¬нҡҢ',
            'bio': 'кіјн•ҷ', 'earth': 'кіјн•ҷ', 'physics': 'кіјн•ҷ', 'chem': 'кіјн•ҷ',
            'modern': 'н•ңкөӯл¬ён•ҷ', 'classic': 'н•ңкөӯл¬ён•ҷ',
            'world1': 'м„ёкі„л¬ён•ҷ', 'world2': 'м„ёкі„л¬ён•ҷ', 'world': 'м„ёкі„л¬ён•ҷ',
            'person1': 'мқёл¬ј', 'person2': 'мқёл¬ј', 'people': 'мқёл¬ј',
            'people1': 'мқёл¬ј', 'people2': 'мқёл¬ј'
          };
          const fieldName = fieldMap[subjectCode] || 'кё°нғҖ';

          // лӢЁмӣҗлӘ… мғқм„ұ (мӣҗліё лӢЁмӣҗлІҲнҳё к·ёлҢҖлЎң мӮ¬мҡ©, +40 ліҖнҷҳ м ңкұ°)
          const unitTitle = `${subjectName} ${unitNumber}`;

          // н•ҷмҠөмӢӨм—җ м¶”к°Җ
          existingTasks.push({
            id: unitId,
            title: unitTitle,
            series: series || 'BRAINUP',
            field: fieldName,
            subject: subjectName,
            isAI: true,
            assignedAt: now,
            originalGrade: gradeInfo.text // мӣҗлһҳ л“ұкёү кё°лЎқ
          });

          existingAIUnitIds.add(unitId);
          assignedCount++;

          // рҹ”Ҙ LearningLogм—җлҸ„ aiTaskAssignedAt м ҖмһҘ (н•ҷмҠө кё°лЎқ н…Ңмқҙлё”м—җ н‘ңмӢң)
          await LearningLog.updateOne(
            { grade, name, unit: unitId },
            { $set: { aiTaskAssignedAt: now } }
          );

          console.log(`вң… [${name}] AI кіјм ң л¶Җм—¬: ${unitTitle} (${gradeInfo.text}, мөңмў…мҷ„лЈҢ: ${finalCompletedAt.toLocaleString('ko-KR')})`);
        }
      }

      if (assignedCount > 0) {
        // UserProgress м ҖмһҘ
        progress.studyRoom = {
          assignedTasks: existingTasks,
          lastAIAssignedAt: now
        };
        await progress.save();

        console.log(`рҹҺү ${name} н•ҷмғқм—җкІҢ ${assignedCount}к°ң AI кіјм ң л¶Җм—¬ мҷ„лЈҢ`);
      }
    }

    console.log('рҹӨ– [NEW] AI мһҗлҸҷ кіјм ң л¶Җм—¬ мҷ„лЈҢ (л“ұкёү кё°л°ҳ):', new Date().toISOString());

    // ========== мҳӨлӢө кё°л°ҳ AI м¶”мІңкіјм ң лЎңм§Ғ (мӨ‘мӢ¬л¬ёлӢЁ мҳӨлӢө + л¬ём ң мҳӨлӢө >= 3нҡҢ) ==========
    console.log('рҹҺҜ [мҳӨлӢө кё°л°ҳ] AI м¶”мІңкіјм ң л¶Җм—¬ мӢңмһ‘...');

    // LearningBehaviorм—җм„ң мҳӨлӢө лҚ°мқҙн„° мЎ°нҡҢ
    const behaviorData = await LearningBehavior.find({});
    console.log(`рҹ“Ҡ мЎ°нҡҢлҗң н–үлҸҷ лҚ°мқҙн„° мҲҳ: ${behaviorData.length}к°ң`);

    // мҳӨлӢө кё°мӨҖ: мӨ‘мӢ¬л¬ёлӢЁ мҳӨлӢө + л¬ём ң мҳӨлӢө >= 3нҡҢ, 12мӢңк°„ кІҪкіј
    const ERROR_THRESHOLD = 3;
    const WAIT_HOURS_FOR_ERROR = 12; // 12мӢңк°„ нӣ„ л¶Җм—¬

    // н•ҷмғқлі„лЎң к·ёлЈ№нҷ”
    const behaviorByStudent = {};
    for (const behavior of behaviorData) {
      const studentKey = `${behavior.grade}::${behavior.name}`;
      if (!behaviorByStudent[studentKey]) {
        behaviorByStudent[studentKey] = {
          grade: behavior.grade,
          name: behavior.name,
          behaviors: []
        };
      }
      behaviorByStudent[studentKey].behaviors.push(behavior);
    }

    let errorBasedAssignedCount = 0;

    for (const studentKey of Object.keys(behaviorByStudent)) {
      const studentData = behaviorByStudent[studentKey];
      const { grade, name, behaviors } = studentData;

      // UserProgress мЎ°нҡҢ
      let progress = await UserProgress.findOne({ grade, name });
      if (!progress) {
        progress = new UserProgress({
          grade,
          name,
          studyRoom: { assignedTasks: [] }
        });
      }

      const existingTasks = progress.studyRoom?.assignedTasks || [];
      // AI м¶”мІңкіјм ңл§Ң м¶”м¶ң (isAI: trueмқё кІғл§Ң мҠӨнӮө лҢҖмғҒ)
      const existingAIUnitIds2 = new Set(existingTasks.filter(t => t.isAI === true).map(t => {
        const taskId = t.unitId || t.id;
        const match = taskId.match(/([a-z]+\d*_\d+)\.html$/i);
        if (match) return match[1];
        return taskId;
      }));

      let studentAssignedCount = 0;

      for (const behavior of behaviors) {
        const paragraphErrors = behavior.paragraphQuizErrors?.total || 0;
        const problemErrors = behavior.problemErrors?.total || 0;
        const totalErrors = paragraphErrors + problemErrors;

        // мҳӨлӢө н•©кі„к°Җ кё°мӨҖ лҜёл§Ңмқҙл©ҙ мҠӨнӮө
        if (totalErrors < ERROR_THRESHOLD) continue;

        const unitId = behavior.unit;
        if (!unitId) continue;

        // мқҙлҜё AI м¶”мІңкіјм ңлЎң н•ҷмҠөмӢӨм—җ мһҲмңјл©ҙ мҠӨнӮө (мқјл°ҳкіјм ңлҠ” мҠӨнӮө м•Ҳн•Ё)
        if (existingAIUnitIds2.has(unitId)) {
          console.log(`вҸӯпёҸ [мҳӨлӢө] ${name}: ${unitId} мқҙлҜё AI м¶”мІңкіјм ңлЎң мһҲмқҢ вҶ’ мҠӨнӮө`);
          continue;
        }

        // 1мӢңк°„ кІҪкіј нҷ•мқё
        const createdAt = new Date(behavior.createdAt);
        const assignableAt = new Date(createdAt.getTime() + WAIT_HOURS_FOR_ERROR * 60 * 60 * 1000);

        if (now < assignableAt) {
          console.log(`вҸӯпёҸ [мҳӨлӢө] ${name}: ${unitId} м•„м§Ғ лҢҖкё° мӨ‘ (${assignableAt.toLocaleString('ko-KR')}к№Ңм§Җ)`);
          continue;
        }

        // лӢЁмӣҗ м •ліҙ м¶”м¶ң
        const parts = unitId.split('_');
        const subjectCode = parts[0];
        const unitNumber = parts[1] ? parseInt(parts[1], 10) : 1;

        const subjectMap = {
          'geo': 'м§ҖлҰ¬', 'bio': 'мғқл¬ј', 'earth': 'м§Җкө¬кіјн•ҷ', 'physics': 'л¬јлҰ¬', 'chem': 'нҷ”н•ҷ',
          'soc': 'мӮ¬нҡҢл¬ёнҷ”', 'law': 'лІ•', 'pol': 'м •м№ҳкІҪм ң',
          'modern': 'нҳ„лҢҖл¬ён•ҷ', 'classic': 'кі м „л¬ён•ҷ',
          'world1': 'м„ёкі„л¬ён•ҷ1', 'world2': 'м„ёкі„л¬ён•ҷ2', 'world': 'м„ёкі„л¬ён•ҷ1',
          'on_geo': 'м§ҖлҰ¬', 'on_bio': 'мғқл¬ј', 'on_earth': 'м§Җкө¬кіјн•ҷ', 'on_physics': 'л¬јлҰ¬', 'on_chem': 'нҷ”н•ҷ',
          'on_soc': 'мӮ¬нҡҢл¬ёнҷ”', 'on_law': 'лІ•', 'on_pol': 'м •м№ҳкІҪм ң',
          'on_modern': 'нҳ„лҢҖл¬ён•ҷ', 'on_classic': 'кі м „л¬ён•ҷ',
          'on_world1': 'м„ёкі„л¬ён•ҷ1', 'on_world2': 'м„ёкі„л¬ён•ҷ2',
          'people1': 'н•ңкөӯмқёл¬ј', 'people2': 'м„ёкі„мқёл¬ј',
          'on_people1': 'н•ңкөӯмқёл¬ј', 'on_people2': 'м„ёкі„мқёл¬ј'
        };
        const subjectName = subjectMap[subjectCode] || subjectCode;

        const fieldMap = {
          'geo': 'мӮ¬нҡҢ', 'soc': 'мӮ¬нҡҢ', 'law': 'мӮ¬нҡҢ', 'pol': 'мӮ¬нҡҢ',
          'bio': 'кіјн•ҷ', 'earth': 'кіјн•ҷ', 'physics': 'кіјн•ҷ', 'chem': 'кіјн•ҷ',
          'modern': 'н•ңкөӯл¬ён•ҷ', 'classic': 'н•ңкөӯл¬ён•ҷ',
          'world1': 'м„ёкі„л¬ён•ҷ', 'world2': 'м„ёкі„л¬ён•ҷ',
          'people1': 'мқёл¬ј', 'people2': 'мқёл¬ј',
          'on_geo': 'мӮ¬нҡҢ', 'on_soc': 'мӮ¬нҡҢ', 'on_law': 'мӮ¬нҡҢ', 'on_pol': 'мӮ¬нҡҢ',
          'on_bio': 'кіјн•ҷ', 'on_earth': 'кіјн•ҷ', 'on_physics': 'кіјн•ҷ', 'on_chem': 'кіјн•ҷ',
          'on_modern': 'н•ңкөӯл¬ён•ҷ', 'on_classic': 'н•ңкөӯл¬ён•ҷ',
          'on_world1': 'м„ёкі„л¬ён•ҷ', 'on_world2': 'м„ёкі„л¬ён•ҷ',
          'on_people1': 'мқёл¬ј', 'on_people2': 'мқёл¬ј'
        };
        const fieldName = fieldMap[subjectCode] || 'кё°нғҖ';

        const unitTitle = behavior.unitTitle || `${subjectName} ${unitNumber}`;

        // н•ҷмҠөмӢӨм—җ м¶”к°Җ
        existingTasks.push({
          id: unitId,
          title: unitTitle,
          series: 'BRAINUP',
          field: fieldName,
          subject: subjectName,
          isAI: true,
          assignedAt: now,
          assignReason: 'error_based', // мҳӨлӢө кё°л°ҳмһ„мқ„ н‘ңмӢң
          totalErrors: totalErrors // мҳӨлӢө нҡҹмҲҳ кё°лЎқ
        });

        existingAIUnitIds2.add(unitId);
        studentAssignedCount++;
        errorBasedAssignedCount++;

        console.log(`вң… [мҳӨлӢө] ${name}: ${unitTitle} AI кіјм ң л¶Җм—¬ (мҳӨлӢө ${totalErrors}нҡҢ)`);
      }

      if (studentAssignedCount > 0) {
        progress.studyRoom = {
          assignedTasks: existingTasks,
          lastAIAssignedAt: now
        };
        await progress.save();
        console.log(`рҹҺү [мҳӨлӢө] ${name} н•ҷмғқм—җкІҢ ${studentAssignedCount}к°ң AI кіјм ң л¶Җм—¬ мҷ„лЈҢ`);
      }
    }

    console.log(`рҹҺҜ [мҳӨлӢө кё°л°ҳ] AI м¶”мІңкіјм ң л¶Җм—¬ мҷ„лЈҢ: мҙқ ${errorBasedAssignedCount}к°ң`);

  } catch (error) {
    console.error('вқҢ AI мһҗлҸҷ кіјм ң л¶Җм—¬ мҳӨлҘҳ:', error);
  }
}

