// 1. мһҗлҸҷ кіјм ң мҠӨмјҖмӨ„ м ҖмһҘ (POST)
app.post('/api/auto-task-schedule', async (req, res) => {
  try {
    const { studentIds, subjects, days, taskCount } = req.body;

    console.log('рҹ“Ҙ [POST] /api/auto-task-schedule мҡ”мІӯ:', { studentIds, subjects, days, taskCount });

    // мһ…л Ҙ кІҖмҰқ
    if (!studentIds || !Array.isArray(studentIds) || studentIds.length === 0) {
      return res.status(400).json({ success: false, message: 'н•ҷмғқмқ„ м„ нғқн•ҙмЈјм„ёмҡ”.' });
    }
    if (!subjects || !Array.isArray(subjects) || subjects.length === 0) {
      return res.status(400).json({ success: false, message: 'кіјлӘ©мқ„ м„ нғқн•ҙмЈјм„ёмҡ”.' });
    }
    if (!days || !Array.isArray(days) || days.length === 0) {
      return res.status(400).json({ success: false, message: 'мҡ”мқјмқ„ м„ нғқн•ҙмЈјм„ёмҡ”.' });
    }
    if (!taskCount || taskCount < 1 || taskCount > 5) {
      return res.status(400).json({ success: false, message: 'кіјм ң к°ңмҲҳлҠ” 1~5к°ң мӮ¬мқҙм—¬м•ј н•©лӢҲлӢӨ.' });
    }

    const results = [];

    // к°Ғ н•ҷмғқм—җкІҢ мҠӨмјҖмӨ„ м¶”к°Җ
    for (const student of studentIds) {
      // studentIdлҠ” мқҙм ң { grade, name } к°қмІҙ
      const user = await UserProgress.findOne({
        grade: student.grade,
        name: student.name
      });

      if (!user) {
        console.log(`вҡ пёҸ  н•ҷмғқмқ„ м°ҫмқ„ мҲҳ м—ҶмқҢ: ${student.grade} ${student.name}`);
        results.push({ student, success: false, message: 'мӮ¬мҡ©мһҗлҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.' });
        continue;
      }

      // кі мң  мҠӨмјҖмӨ„ ID мғқм„ұ
      const scheduleId = `schedule_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

      // лӢӨмқҢ мӢӨн–ү мҳҲм •мқј кі„мӮ°
      const nextScheduledDate = calculateNextScheduledDate(days);

      const newSchedule = {
        scheduleId,
        subjects,
        days: days.map(d => parseInt(d)),
        taskCount: parseInt(taskCount),
        isActive: true,
        createdAt: new Date(),
        lastExecutedAt: null,
        nextScheduledDate
      };

      // мҠӨмјҖмӨ„ м¶”к°Җ
      if (!user.studyRoom) {
        user.studyRoom = { assignedTasks: [], autoTaskSchedules: [] };
      }
      if (!user.studyRoom.autoTaskSchedules) {
        user.studyRoom.autoTaskSchedules = [];
      }

      user.studyRoom.autoTaskSchedules.push(newSchedule);
      await user.save();

      console.log(`вң… мҠӨмјҖмӨ„ м ҖмһҘ м„ұкіө: ${student.grade} ${student.name} - ${scheduleId}`);
      results.push({ student, success: true, scheduleId });
    }

    const successCount = results.filter(r => r.success).length;
    const failCount = results.filter(r => !r.success).length;

    res.json({
      success: true,
      message: `мҠӨмјҖмӨ„ л“ұлЎқ мҷ„лЈҢ (м„ұкіө: ${successCount}лӘ…, мӢӨнҢЁ: ${failCount}лӘ…)`,
      results
    });

  } catch (error) {
    console.error('мҠӨмјҖмӨ„ м ҖмһҘ мҳӨлҘҳ:', error);
    res.status(500).json({ success: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// лӢӨмқҢ мӢӨн–ү мҳҲм •мқј кі„мӮ° н•ЁмҲҳ
function calculateNextScheduledDate(days) {
  const now = new Date();
  const currentDay = now.getDay(); // 0(мқј) ~ 6(нҶ )
  const sortedDays = days.map(d => parseInt(d)).sort((a, b) => a - b);

  // мҳӨлҠҳ мқҙнӣ„ к°ҖмһҘ к°Җк№Ңмҡҙ мҡ”мқј м°ҫкё°
  let nextDay = sortedDays.find(d => d > currentDay);

  // м—Ҷмңјл©ҙ лӢӨмқҢ мЈј мІ« лІҲм§ё мҡ”мқј
  if (nextDay === undefined) {
    nextDay = sortedDays[0];
  }

  const daysUntilNext = nextDay >= currentDay
    ? nextDay - currentDay
    : 7 - currentDay + nextDay;

  const nextDate = new Date(now);
  nextDate.setDate(now.getDate() + daysUntilNext);
  nextDate.setHours(0, 0, 0, 0);

  return nextDate;
}

