app.patch('/api/auto-task-schedule/:scheduleId/toggle', async (req, res) => {
  try {
    const { scheduleId } = req.params;
    const { grade, name } = req.body;

    console.log(`рҹ“Ҙ [PATCH] /api/auto-task-schedule/${scheduleId}/toggle:`, { grade, name });

    if (!grade || !name) {
      return res.status(400).json({ success: false, message: 'н•ҷл…„кіј мқҙлҰ„мқҙ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    const user = await UserProgress.findOne({
      grade: grade,
      name: name
    });

    if (!user) {
      console.log(`вҡ пёҸ  мӮ¬мҡ©мһҗлҘј м°ҫмқ„ мҲҳ м—ҶмқҢ: ${grade} ${name}`);
      return res.status(404).json({ success: false, message: 'мӮ¬мҡ©мһҗлҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.' });
    }

    const schedule = user.studyRoom?.autoTaskSchedules?.find(s => s.scheduleId === scheduleId);

    if (!schedule) {
      return res.status(404).json({ success: false, message: 'мҠӨмјҖмӨ„мқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.' });
    }

    // мғҒнғң нҶ кёҖ
    schedule.isActive = !schedule.isActive;
    await user.save();

    res.json({
      success: true,
      message: schedule.isActive ? 'мҠӨмјҖмӨ„мқҙ мһ¬к°ңлҗҳм—ҲмҠөлӢҲлӢӨ.' : 'мҠӨмјҖмӨ„мқҙ мқјмӢңм •м§Җлҗҳм—ҲмҠөлӢҲлӢӨ.',
      isActive: schedule.isActive
    });

  } catch (error) {
    console.error('мҠӨмјҖмӨ„ нҶ кёҖ мҳӨлҘҳ:', error);
    res.status(500).json({ success: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

