// лҜёмҷ„лЈҢ лӢЁмӣҗ мЎ°нҡҢ н•ЁмҲҳ
async function getIncompleteUnits(grade, name, subjectPath) {
  try {
    // лӘЁл“  лӢЁмӣҗ
    const allUnits = SUBJECT_UNITS_MAP[subjectPath] || [];

    // мҷ„лЈҢлҗң лӢЁмӣҗ мЎ°нҡҢ (н•ҷмҠө лЎңк·ём—җм„ң)
    const completedLogs = await LearningLog.find({
      grade,
      name,
      subject: SUBJECT_META_MAP[subjectPath]?.subject
    });

    const completedUnits = new Set(completedLogs.map(log => log.unitId));

    // лҜёмҷ„лЈҢ лӢЁмӣҗ н•„н„°л§Ғ
    const incompleteUnits = allUnits.filter(unit => !completedUnits.has(unit));

    return incompleteUnits;
  } catch (error) {
    console.error('лҜёмҷ„лЈҢ лӢЁмӣҗ мЎ°нҡҢ мҳӨлҘҳ:', error);
    return [];
  }
}

// мһҗлҸҷ кіјм ң л¶Җм—¬ н•ЁмҲҳ
async function executeAutoTaskSchedules() {
  try {
    console.log('рҹ•җ мһҗлҸҷ кіјм ң л¶Җм—¬ мҠӨмјҖмӨ„лҹ¬ мӢӨн–ү мӢңмһ‘...');

    const today = new Date().getDay(); // 0(мқј) ~ 6(нҶ )

    // лӘЁл“  мӮ¬мҡ©мһҗ мЎ°нҡҢ
    const users = await UserProgress.find({
      'studyRoom.autoTaskSchedules': { $exists: true, $ne: [] }
    });

    let totalSchedules = 0;
    let successCount = 0;
    let failCount = 0;

    for (const user of users) {
      const schedules = user.studyRoom?.autoTaskSchedules || [];

      for (const schedule of schedules) {
        // нҷңм„ұнҷ”лҗҳм§Җ м•ҠмқҖ мҠӨмјҖмӨ„мқҖ кұҙл„Ҳлӣ°кё°
        if (!schedule.isActive) continue;

        // мҳӨлҠҳ мҡ”мқјмқҙ мӢӨн–ү мҡ”мқјм—җ нҸ¬н•ЁлҗҳлҠ”м§Җ нҷ•мқё
        if (!schedule.days.includes(today)) continue;

        totalSchedules++;

        try {
          // кіјлӘ©лі„лЎң кіјм ң л¶Җм—¬
          let tasksAssigned = 0;

          for (const subjectPath of schedule.subjects) {
            // лҜёмҷ„лЈҢ лӢЁмӣҗ мЎ°нҡҢ
            const incompleteUnits = await getIncompleteUnits(user.grade, user.name, subjectPath);

            if (incompleteUnits.length === 0) {
              console.log(`вҡ пёҸ ${user.name} - ${subjectPath}: лҜёмҷ„лЈҢ лӢЁмӣҗ м—ҶмқҢ`);
              continue;
            }

            // taskCountл§ҢнҒј мҲңм°Ём ҒмңјлЎң кіјм ң л¶Җм—¬
            const unitsToAssign = incompleteUnits.slice(0, schedule.taskCount);
            const meta = SUBJECT_META_MAP[subjectPath];

            for (const unitId of unitsToAssign) {
              const newTask = {
                id: unitId,
                unitId: unitId,
                title: `${meta.subject} ${unitId}`,
                series: meta.series,
                field: meta.field,
                subject: meta.subject,
                isAI: false,
                assignedAt: new Date(),
                dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7мқј нӣ„
                status: 'pending',
                progress: 0
              };

              if (!user.studyRoom.assignedTasks) {
                user.studyRoom.assignedTasks = [];
              }

              user.studyRoom.assignedTasks.push(newTask);
              tasksAssigned++;
            }
          }

          // мҠӨмјҖмӨ„ м—…лҚ°мқҙнҠё
          schedule.lastExecutedAt = new Date();
          schedule.nextScheduledDate = calculateNextScheduledDate(schedule.days);

          await user.save();

          console.log(`вң… ${user.name}: ${tasksAssigned}к°ң кіјм ң л¶Җм—¬ мҷ„лЈҢ`);
          successCount++;

        } catch (error) {
          console.error(`вқҢ ${user.name} кіјм ң л¶Җм—¬ мӢӨнҢЁ:`, error);
          failCount++;
        }
      }
    }

    console.log(`рҹҺү мһҗлҸҷ кіјм ң л¶Җм—¬ мҷ„лЈҢ - мҙқ ${totalSchedules}к°ң мҠӨмјҖмӨ„ (м„ұкіө: ${successCount}, мӢӨнҢЁ: ${failCount})`);

  } catch (error) {
    console.error('мһҗлҸҷ кіјм ң л¶Җм—¬ мҠӨмјҖмӨ„лҹ¬ мҳӨлҘҳ:', error);
  }
}

