// л¬ён•ҙл Ҙ м§„лӢЁн…ҢмҠӨнҠё м •лӢө л°°м—ҙ (25л¬ём ң) - diagnostic_reading_test.htmlкіј лҸҷмқјн•ҳкІҢ мң м§Җ
const diagnosticCorrectAnswers = [2, 0, 1, 1, 2, 1, 2, 1, 2, 3, 2, 0, 1, 1, 2, 1, 1, 1, 2, 2, 1, 0, 1, 1, 2];

// score кі„мӮ° н•ЁмҲҳ (answers л°°м—ҙлЎң м •лӢө к°ңмҲҳ кі„мӮ°)
function calculateScoreFromAnswers(answers) {
  if (!answers || !Array.isArray(answers) || answers.length === 0) return 0;
  let correctCount = 0;
  answers.forEach((userAnswer, index) => {
    if (index < diagnosticCorrectAnswers.length && userAnswer === diagnosticCorrectAnswers[index]) {
      correctCount++;
    }
  });
  return correctCount;
}

// л“ұкёү л°Ҹ мӢңлҰ¬мҰҲ кі„мӮ° н•ЁмҲҳ
function calculateGradeAndSeries(score, studentGrade) {
  const isElementary = ['3н•ҷл…„', '4н•ҷл…„', '5н•ҷл…„', '6н•ҷл…„'].includes(studentGrade);
  let grade, series;

  if (isElementary) {
    // мҙҲл“ұ кё°мӨҖ: 23~25 л”Ҙ, 19~22 н•Ҹ, 14~18 м—…, 0~13 мҳЁ
    if (score >= 23) {
      grade = "мөңмҡ°мҲҳ (A+) / мҲҳлҠҘлӮҙмӢ  1~2л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN л”Ҙ";
    } else if (score >= 19) {
      grade = "мҡ°мҲҳ (A) / мҲҳлҠҘлӮҙмӢ  3л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN н•Ҹ";
    } else if (score >= 14) {
      grade = "ліҙнҶө (C+) / мҲҳлҠҘлӮҙмӢ  4л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN м—…";
    } else {
      grade = "кё°мҙҲ (D) / мҲҳлҠҘлӮҙмӢ  5л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN мҳЁ";
    }
  } else {
    // мӨ‘кі л“ұ кё°мӨҖ: 24~25 л”Ҙ, 22~23 н•Ҹ, 16~21 м—…, 0~15 мҳЁ
    if (score >= 24) {
      grade = "мөңмҡ°мҲҳ (A+) / мҲҳлҠҘлӮҙмӢ  1~2л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN л”Ҙ";
    } else if (score >= 22) {
      grade = "мҡ°мҲҳ (A) / мҲҳлҠҘлӮҙмӢ  3л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN н•Ҹ";
    } else if (score >= 16) {
      grade = "ліҙнҶө (C+) / мҲҳлҠҘлӮҙмӢ  4л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN м—…";
    } else {
      grade = "кё°мҙҲ (D) / мҲҳлҠҘлӮҙмӢ  5л“ұкёү(мҳҲмёЎ)";
      series = "BRAIN мҳЁ";
    }
  }

  return { grade, series };
}

// мҲҳк°•мӢ мІӯ лӘ©лЎқ мЎ°нҡҢ (мҠҲнҚј кҙҖлҰ¬мһҗмҡ©)
app.get("/api/course-applications", async (req, res) => {
  try {
    const applications = await CourseApplication.find().sort({ createdAt: -1 });

    // answers л°°м—ҙмқҙ мһҲмңјл©ҙ н•ӯмғҒ м җмҲҳ мһ¬кі„мӮ°, л“ұкёү/мӢңлҰ¬мҰҲлҸ„ н•ӯмғҒ мһ¬кі„мӮ°
    const applicationsWithScore = applications.map(app => {
      const appObj = app.toObject();
      // answers л°°м—ҙмқҙ мһҲмңјл©ҙ н•ӯмғҒ м җмҲҳ мһ¬кі„мӮ°
      if (appObj.answers && appObj.answers.length > 0) {
        appObj.score = calculateScoreFromAnswers(appObj.answers);
      }
      // л“ұкёүкіј мӢңлҰ¬мҰҲ н•ӯмғҒ мһ¬кі„мӮ°
      if (appObj.studentGrade) {
        const { grade, series } = calculateGradeAndSeries(appObj.score || 0, appObj.studentGrade);
        appObj.grade = grade;
        appObj.series = series;
      }
      return appObj;
    });

    res.json({ success: true, data: applicationsWithScore });
  } catch (error) {
    console.error("мҲҳк°•мӢ мІӯ мЎ°нҡҢ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "мЎ°нҡҢ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// к°ңлі„ мҲҳк°•мӢ мІӯ мӢңн—ҳм§Җ мЎ°нҡҢ (кҙҖлҰ¬мһҗмҡ© - IDлЎң мЎ°нҡҢ)
