// н•ҷмғқ м¶”к°Җ API (лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ©)
app.post("/api/admin/branch/add-student", async (req, res) => {
  try {
    // м„ём…ҳм—җм„ң кҙҖлҰ¬мһҗ м •ліҙ нҷ•мқё
    if (!req.session || !req.session.admin || !req.session.admin.academyName) {
      return res.status(401).json({ success: false, message: "лЎңк·ёмқёмқҙ н•„мҡ”н•©лӢҲлӢӨ." });
    }

    const { grade, name, school, number, classNum } = req.body;

    if (!name || !number) {
      return res.status(400).json({ success: false, message: "мқҙлҰ„кіј лІҲнҳёлҠ” н•„мҲҳмһ…лӢҲлӢӨ." });
    }

    // кҙҖлҰ¬мһҗмқҳ н•ҷкөҗ/н•ҷл…„/л°ҳ м •ліҙ мӮ¬мҡ©
    const academyName = req.session.admin.academyName;
    const adminGrade = req.session.admin.grade || grade || "";
    const adminClassNum = req.session.admin.classNum || classNum || "";

    // м „нҷ”лІҲнҳё(ID) мһҗлҸҷ мғқм„ұ: н•ҷл…„+л°ҳ+лІҲнҳё мЎ°н•© (мҳҲ: 4н•ҷл…„7л°ҳ15лІҲ вҶ’ 040715)
    // н•ҷл…„м—җм„ң мҲ«мһҗ м¶”м¶ң
    const gradeNum = (adminGrade || "").replace(/[^0-9]/g, "").padStart(2, "0");
    // л°ҳм—җм„ң мҲ«мһҗ м¶”м¶ң
    const classNumDigit = (adminClassNum || "").replace(/[^0-9]/g, "").padStart(2, "0");
    // лІҲнҳё нҢЁл”©
    const studentNum = String(number).padStart(2, "0");
    // мһҗлҸҷ мғқм„ұ ID
    const autoPhone = gradeNum + classNumDigit + studentNum;

    // мқҙлҜё мЎҙмһ¬н•ҳлҠ” м „нҷ”лІҲнҳёмқём§Җ нҷ•мқё
    const existingUser = await User.findOne({ phone: autoPhone });
    if (existingUser) {
      return res.status(400).json({ success: false, message: "мқҙлҜё л“ұлЎқлҗң лІҲнҳёмһ…лӢҲлӢӨ. (ID: " + autoPhone + ")" });
    }

    // мғҲ н•ҷмғқ мғқм„ұ
    const newUser = new User({
      grade: adminGrade,
      name: name.trim(),
      phone: autoPhone,
      school: school ? school.trim() : academyName,
      classNum: adminClassNum,
      studentNum: number.trim(),
      status: "approved",
      createdAt: new Date()
    });

    await newUser.save();
    console.log("вң… н•ҷмғқ м¶”к°Җ мҷ„лЈҢ:", newUser.name, "ID:", autoPhone);

    res.json({ success: true, message: "н•ҷмғқмқҙ м¶”к°Җлҗҳм—ҲмҠөлӢҲлӢӨ. (ID: " + autoPhone + ")", data: newUser });
  } catch (error) {
    console.error("н•ҷмғқ м¶”к°Җ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "н•ҷмғқ м¶”к°Җ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// н•ҷмғқ м¶”к°Җ API (н•ҷмӣҗ кҙҖлҰ¬мһҗмҡ©)
app.post("/api/admin/academy/add-student", async (req, res) => {
  try {
    // м„ём…ҳм—җм„ң кҙҖлҰ¬мһҗ м •ліҙ нҷ•мқё
    if (!req.session || !req.session.admin || !req.session.admin.academyName) {
      return res.status(401).json({ success: false, message: "лЎңк·ёмқёмқҙ н•„мҡ”н•©лӢҲлӢӨ." });
    }

    const { grade, name, academyName, number } = req.body;

    if (!grade || !name || !number) {
      return res.status(400).json({ success: false, message: "н•ҷл…„, мқҙлҰ„, м „нҷ”лІҲнҳёлҠ” н•„мҲҳмһ…лӢҲлӢӨ." });
    }

    // кҙҖлҰ¬мһҗмқҳ н•ҷмӣҗ м •ліҙ мӮ¬мҡ©
    const adminAcademyName = req.session.admin.academyName;

    // м „нҷ”лІҲнҳё(ID): 11мһҗлҰ¬ м „мІҙ мӮ¬мҡ© (н•ҳмқҙн”Ҳ м ңкұ°)
    const phone = String(number).replace(/[^0-9]/g, '');

    // м „нҷ”лІҲнҳё 11мһҗлҰ¬ кІҖмҰқ
    if (phone.length !== 11) {
      return res.status(400).json({ success: false, message: "м „нҷ”лІҲнҳёлҘј 11мһҗлҰ¬лЎң мһ…л Ҙн•ҙмЈјм„ёмҡ”." });
    }

    // мқҙлҜё мЎҙмһ¬н•ҳлҠ” м „нҷ”лІҲнҳёмқём§Җ нҷ•мқё
    const existingUser = await User.findOne({ phone: phone });
    if (existingUser) {
      return res.status(400).json({ success: false, message: "мқҙлҜё л“ұлЎқлҗң м „нҷ”лІҲнҳёмһ…лӢҲлӢӨ. (ID: " + phone + ")" });
    }

    // мғҲ н•ҷмғқ мғқм„ұ
    const newUser = new User({
      grade: grade.trim(),
      name: name.trim(),
      phone: phone,
      academyName: adminAcademyName,  // н•ҷмӣҗлӘ… н•„л“ң мӮ¬мҡ©
      userType: "academy",  // н•ҷмӣҗмҡ© н•ҷмғқ нғҖмһ… н•„мҲҳ!
      status: "approved",
      createdAt: new Date()
    });

    await newUser.save();
    console.log("вң… н•ҷмӣҗ н•ҷмғқ м¶”к°Җ мҷ„лЈҢ:", newUser.name, "ID:", phone, "н•ҷмӣҗ:", adminAcademyName);

    res.json({ success: true, message: "н•ҷмғқмқҙ м¶”к°Җлҗҳм—ҲмҠөлӢҲлӢӨ. (ID: " + phone + ")", data: newUser });
  } catch (error) {
    console.error("н•ҷмӣҗ н•ҷмғқ м¶”к°Җ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "н•ҷмғқ м¶”к°Җ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// м§„лӢЁн…ҢмҠӨнҠё лӘ©лЎқ мЎ°нҡҢ (лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ© - м§Җм җлӘ…/н•ҷл…„ н•„н„°л§Ғ)
app.get("/api/admin/diagnostic-tests", async (req, res) => {
  try {
    // м„ём…ҳм—җм„ң кҙҖлҰ¬мһҗ м •ліҙ нҷ•мқё
    if (!req.session || !req.session.admin || !req.session.admin.academyName) {
      return res.status(401).json({ success: false, message: "лЎңк·ёмқёмқҙ н•„мҡ”н•©лӢҲлӢӨ." });
    }

    const academyName = req.session.admin.academyName;
    const adminGrade = req.session.admin.grade;
    const adminClassNum = req.session.admin.classNum;

    // м§Җм җлӘ…мңјлЎң н•„н„°л§Ғн•ҳм—¬ мЎ°нҡҢ (м§Җм җлӘ…м—җ academyNameмқҙ нҸ¬н•Ёлҗң кІҪмҡ° л§Өм№ӯ)
    const filter = {
      branchName: { $regex: academyName, $options: 'i' }
    };

    // вң… "м „мІҙ" н•ҷл…„ м„ нғқ мӢң н•ҷл…„ н•„н„°л§Ғ кұҙл„Ҳлӣ°кё° (н•ҙлӢ№ н•ҷкөҗ м „мІҙ н•ҷл…„ н‘ңмӢң)
    if (adminGrade && adminGrade !== "м „мІҙ") {
      filter.studentGrade = adminGrade;
    }

    // вң… "м „мІҙ" л°ҳ м„ нғқ мӢң л°ҳ н•„н„°л§Ғ кұҙл„Ҳлӣ°кё° (н•ҙлӢ№ н•ҷкөҗ м „мІҙ л°ҳ н‘ңмӢң)
    if (adminClassNum && adminClassNum !== "м „мІҙ") {
      filter.studentClassNum = adminClassNum;
    }

    const tests = await DiagnosticTest.find(filter).sort({ createdAt: -1 });

    res.json({
      success: true,
      data: tests,
      academyName: academyName,
      adminGrade: adminGrade,
      adminClassNum: adminClassNum,
      userType: req.session.admin.userType || 'school'  // н•ҷмӣҗ/н•ҷкөҗ кө¬л¶„
    });
  } catch (error) {
    console.error("лёҢлһңм№ҳ кҙҖлҰ¬мһҗ м§„лӢЁн…ҢмҠӨнҠё мЎ°нҡҢ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "мЎ°нҡҢ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// мҲҳк°•мӢ мІӯ лӘ©лЎқ мЎ°нҡҢ (лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ© - м§Җм җлӘ… н•„н„°л§Ғ)
app.get("/api/admin/course-applications", async (req, res) => {
  try {
    // м„ём…ҳм—җм„ң кҙҖлҰ¬мһҗ м •ліҙ нҷ•мқё
    if (!req.session || !req.session.admin || !req.session.admin.academyName) {
      return res.status(401).json({ success: false, message: "лЎңк·ёмқёмқҙ н•„мҡ”н•©лӢҲлӢӨ." });
    }

    const academyName = req.session.admin.academyName;
    const adminGrade = req.session.admin.grade;
    const adminClassNum = req.session.admin.classNum;

    // м§Җм җлӘ…мңјлЎң н•„н„°л§Ғн•ҳм—¬ мЎ°нҡҢ (м§Җм җлӘ…м—җ academyNameмқҙ нҸ¬н•Ёлҗң кІҪмҡ° л§Өм№ӯ)
    const filter = {
      branchName: { $regex: academyName, $options: 'i' }
    };

    // вң… "м „мІҙ" н•ҷл…„ м„ нғқ мӢң н•ҷл…„ н•„н„°л§Ғ кұҙл„Ҳлӣ°кё°
    if (adminGrade && adminGrade !== "м „мІҙ") {
      filter.studentGrade = adminGrade;
    }

    // вң… л°ҳ н•„н„°л§Ғ: кё°мЎҙ лҚ°мқҙн„°лҠ” studentClassNumмқҙ м—ҶмңјлҜҖлЎң, н•ҙлӢ№ л°ҳмқҙкұ°лӮҳ л№Ҳ к°’мқё кІҪмҡ° лӘЁл‘җ нҸ¬н•Ё
    if (adminClassNum && adminClassNum !== "м „мІҙ") {
      filter.$or = [
        { studentClassNum: adminClassNum },
        { studentClassNum: { $exists: false } },
        { studentClassNum: '' },
        { studentClassNum: null }
      ];
    }

    const applications = await CourseApplication.find(filter).sort({ createdAt: -1 });

    // answers л°°м—ҙмқҙ мһҲмңјл©ҙ н•ӯмғҒ м җмҲҳ мһ¬кі„мӮ°, л“ұкёү/мӢңлҰ¬мҰҲлҸ„ н•ӯмғҒ мһ¬кі„мӮ°
    const applicationsWithScore = applications.map(app => {
      const appObj = app.toObject();
      // answers л°°м—ҙмқҙ мһҲмңјл©ҙ н•ӯмғҒ м җмҲҳ мһ¬кі„мӮ°
      if (appObj.answers && appObj.answers.length > 0) {
        appObj.score = calculateScoreFromAnswers(appObj.answers);
      }
      // л“ұкёүкіј мӢңлҰ¬мҰҲ н•ӯмғҒ мһ¬кі„мӮ°
      if (appObj.studentGrade) {
        const { grade, series } = calculateGradeAndSeries(appObj.score || 0, appObj.studentGrade);
        appObj.grade = grade;
        appObj.series = series;
      }
      return appObj;
    });

    res.json({ success: true, data: applicationsWithScore, academyName: academyName, adminGrade: adminGrade, adminClassNum: adminClassNum });
  } catch (error) {
    console.error("лёҢлһңм№ҳ кҙҖлҰ¬мһҗ мҲҳк°•мӢ мІӯ мЎ°нҡҢ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "мЎ°нҡҢ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// м§„лӢЁн…ҢмҠӨнҠё м„ нғқмӮӯм ң (лёҢлһңм№ҳ кҙҖлҰ¬мһҗмҡ©)
