// ===== н•ҷмҠө м§„н–ү лҚ°мқҙн„° API (localStorage лҢҖмІҙ) =====

// лӢЁмӣҗлі„ н•ҷмҠө м§„н–ү лҚ°мқҙн„° м ҖмһҘ
app.post("/api/unit-progress/save", async (req, res) => {
  try {
    const { grade, name, unit, data } = req.body;
    console.log('[unit-progress/save] мҡ”мІӯ:', { grade, name, unit, data });

    if (!grade || !name || !unit) {
      return res.status(400).json({ success: false, message: "grade, name, unitмқҖ н•„мҲҳмһ…лӢҲлӢӨ." });
    }

    let userProgress = await UserProgress.findOne({ grade, name });
    console.log('[unit-progress/save] кё°мЎҙ л¬ём„ң:', userProgress ? 'мһҲмқҢ' : 'м—ҶмқҢ');

    if (!userProgress) {
      userProgress = new UserProgress({ grade, name });
    }

    // unitProgress Mapм—җ лҚ°мқҙн„° м ҖмһҘ
    if (!userProgress.unitProgress) {
      userProgress.unitProgress = new Map();
    }

    // Mapмқҙ м•„лӢҢ кІҪмҡ° MapмңјлЎң ліҖнҷҳ
    if (!(userProgress.unitProgress instanceof Map)) {
      console.log('[unit-progress/save] unitProgressлҘј MapмңјлЎң ліҖнҷҳ');
      userProgress.unitProgress = new Map(Object.entries(userProgress.unitProgress || {}));
    }

    let existingData = userProgress.unitProgress.get(unit) || {};
    // Mongoose subdocumentлҘј мқјл°ҳ к°қмІҙлЎң ліҖнҷҳ
    if (existingData && typeof existingData.toObject === 'function') {
      existingData = existingData.toObject();
    }
    console.log('[unit-progress/save] кё°мЎҙ лҚ°мқҙн„°:', existingData);

    const updatedData = {
      ...existingData,
      ...data,
      lastUpdated: new Date()
    };
    console.log('[unit-progress/save] м—…лҚ°мқҙнҠёлҗң лҚ°мқҙн„°:', updatedData);

    userProgress.unitProgress.set(unit, updatedData);

    // мҷ„лЈҢ нҺҳмқҙм§Җ лӘ©лЎқ м—…лҚ°мқҙнҠё
    if (data.completedPages && Array.isArray(data.completedPages)) {
      if (!userProgress.completedPages) {
        userProgress.completedPages = [];
      }
      data.completedPages.forEach(pageId => {
        if (!userProgress.completedPages.includes(pageId)) {
          userProgress.completedPages.push(pageId);
        }
      });
    }

    await userProgress.save();
    console.log('[unit-progress/save] м ҖмһҘ мҷ„лЈҢ');

    res.json({ success: true, message: "н•ҷмҠө м§„н–ү лҚ°мқҙн„° м ҖмһҘ мҷ„лЈҢ" });
  } catch (error) {
    console.error("н•ҷмҠө м§„н–ү лҚ°мқҙн„° м ҖмһҘ мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "м ҖмһҘ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// лӢЁмӣҗлі„ н•ҷмҠө м§„н–ү лҚ°мқҙн„° л¶Ҳлҹ¬мҳӨкё°
app.get("/api/unit-progress/load", async (req, res) => {
  try {
    const { grade, name, unit } = req.query;
    console.log('[unit-progress/load] мҡ”мІӯ:', { grade, name, unit });

    if (!grade || !name) {
      return res.status(400).json({ success: false, message: "grade, nameмқҖ н•„мҲҳмһ…лӢҲлӢӨ." });
    }

    const userProgress = await UserProgress.findOne({ grade, name });
    console.log('[unit-progress/load] л¬ём„ң:', userProgress ? 'мһҲмқҢ' : 'м—ҶмқҢ');

    if (!userProgress) {
      return res.json({ success: true, data: null, completedPages: [] });
    }

    // л””лІ„к·ё лЎңк·ё м ңкұ° (м„ұлҠҘ н–ҘмғҒ)

    // нҠ№м • лӢЁмӣҗ лҚ°мқҙн„° л°ҳнҷҳ
    if (unit) {
      let unitData = null;
      if (userProgress.unitProgress) {
        // Mapмқё кІҪмҡ°
        if (userProgress.unitProgress instanceof Map) {
          unitData = userProgress.unitProgress.get(unit);
        } else {
          // Objectмқё кІҪмҡ°
          unitData = userProgress.unitProgress[unit];
        }
      }
      return res.json({
        success: true,
        data: unitData || null,
        completedPages: userProgress.completedPages || []
      });
    }

    // м „мІҙ лҚ°мқҙн„° л°ҳнҷҳ (unit лҜём§Җм • мӢң)
    const allUnitProgress = {};
    if (userProgress.unitProgress) {
      if (userProgress.unitProgress instanceof Map) {
        userProgress.unitProgress.forEach((value, key) => {
          allUnitProgress[key] = value;
        });
      } else {
        Object.assign(allUnitProgress, userProgress.unitProgress);
      }
    }

    res.json({
      success: true,
      data: allUnitProgress,
      completedPages: userProgress.completedPages || []
    });
  } catch (error) {
    console.error("н•ҷмҠө м§„н–ү лҚ°мқҙн„° л¶Ҳлҹ¬мҳӨкё° мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "л¶Ҳлҹ¬мҳӨкё° мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

// лӢЁмӣҗлі„ н•ҷмҠө м§„н–ү лҚ°мқҙн„° мӮӯм ң (лҰ¬м…Ӣ)
app.post("/api/unit-progress/reset", async (req, res) => {
  try {
    const { grade, name, unit } = req.body;

    if (!grade || !name || !unit) {
      return res.status(400).json({ success: false, message: "grade, name, unitмқҖ н•„мҲҳмһ…лӢҲлӢӨ." });
    }

    const userProgress = await UserProgress.findOne({ grade, name });

    if (!userProgress) {
      return res.json({ success: true, message: "мӮӯм ңн•  лҚ°мқҙн„°к°Җ м—ҶмҠөлӢҲлӢӨ." });
    }

    // н•ҙлӢ№ лӢЁмӣҗ лҚ°мқҙн„° мӮӯм ң
    if (userProgress.unitProgress) {
      userProgress.unitProgress.delete(unit);
    }

    // completedPagesм—җм„ң н•ҙлӢ№ лӢЁмӣҗ кҙҖл Ё нҺҳмқҙм§Җ м ңкұ°
    if (userProgress.completedPages) {
      userProgress.completedPages = userProgress.completedPages.filter(
        pageId => !pageId.startsWith(unit)
      );
    }

    await userProgress.save();

    res.json({ success: true, message: "н•ҷмҠө м§„н–ү лҚ°мқҙн„° мӮӯм ң мҷ„лЈҢ" });
  } catch (error) {
    console.error("н•ҷмҠө м§„н–ү лҚ°мқҙн„° мӮӯм ң мҳӨлҘҳ:", error);
    res.status(500).json({ success: false, message: "мӮӯм ң мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ." });
  }
});

