// ліҙмҷ„ н•ҷмҠө мӢңн—ҳм§Җ мғқм„ұ
app.post('/api/supplement-exams', async (req, res) => {
  try {
    const { areaKey, title, questions } = req.body;

    if (!areaKey || !DETAIL_AREA_INFO[areaKey]) {
      return res.status(400).json({ ok: false, message: 'мң нҡЁн•ҳм§Җ м•ҠмқҖ мҳҒм—ӯмһ…лӢҲлӢӨ.' });
    }

    // examId мһҗлҸҷ мғқм„ұ (supplement_мҳҒм—ӯнӮӨ_лІҲнҳё)
    const existingCount = await SupplementExam.countDocuments({ areaKey });
    const examId = `supplement_${areaKey}_${existingCount + 1}`;

    const exam = await SupplementExam.create({
      examId,
      areaKey,
      areaName: DETAIL_AREA_INFO[areaKey].name,
      parentArea: DETAIL_AREA_INFO[areaKey].parent,
      title: title || `${DETAIL_AREA_INFO[areaKey].name} ліҙмҷ„ н•ҷмҠө ${existingCount + 1}`,
      questionCount: questions ? questions.length : 0,
      questions: questions || []
    });

    res.json({ ok: true, exam });
  } catch (err) {
    console.error('вқҢ [POST /api/supplement-exams] мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'мғқм„ұ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.', error: err.message });
  }
});

