// мӨ‘ліө м°ёк°Җ мІҙнҒ¬ API (к°ҷмқҖ мқҙлІӨнҠё + к°ҷмқҖ мӮ¬лһҢ = мӨ‘ліө м°ёк°Җ л¶Ҳк°Җ)
app.get('/api/speed-vocab-king/check-event', async (req, res) => {
  try {
    const { eventName, grade, name, phone } = req.query;

    if (!eventName || !grade || !name || !phone) {
      return res.status(400).json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    // к°ҷмқҖ мқҙлІӨнҠёлӘ… + к°ҷмқҖ мӮ¬лһҢ(н•ҷл…„/мқҙлҰ„/м „нҷ”лІҲнҳё)мңјлЎң мқҙлҜё м°ёк°Җн–ҲлҠ”м§Җ нҷ•мқё
    const existing = await SpeedVocabKing.findOne({
      eventName,
      grade,
      name,
      phone
    }).lean();

    res.json({
      ok: true,
      exists: !!existing,
      message: existing ? 'мқҙлҜё н•ҙлӢ№ мқҙлІӨнҠём—җ м°ёк°Җн•ҳм…ЁмҠөлӢҲлӢӨ. лӢӨлҘё мқҙлІӨнҠёлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.' : ''
    });
  } catch (err) {
    console.error('мӨ‘ліө м°ёк°Җ мІҙнҒ¬ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// кІ°кіј м ҖмһҘ API
app.post('/api/speed-vocab-king/save', async (req, res) => {
  try {
    const { eventName, grade, name, phone, correctCount, totalTime, totalQuestions } = req.body;

    if (!eventName || !grade || !name || !phone) {
      return res.status(400).json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ лҲ„лқҪлҗҳм—ҲмҠөлӢҲлӢӨ.' });
    }

    const result = new SpeedVocabKing({
      eventName,
      grade,
      name,
      phone,
      correctCount: correctCount || 0,
      totalTime: totalTime || 0,
      totalQuestions: totalQuestions || 10
    });

    await result.save();

    res.json({ ok: true, message: 'кІ°кіјк°Җ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ.' });
  } catch (err) {
    console.error('мҠӨн”јл“ң м–ҙнңҳмҷ• кІ°кіј м ҖмһҘ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// мҲңмң„ мЎ°нҡҢ API
app.get('/api/speed-vocab-king/ranking', async (req, res) => {
  try {
    const { eventName } = req.query;

    if (!eventName) {
      return res.status(400).json({ ok: false, message: 'мқҙлІӨнҠёлӘ…мқҙ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    // мқҙлІӨнҠёлі„ мҲңмң„ мЎ°нҡҢ (л§һнһҢ к°ңмҲҳ лӮҙлҰјм°ЁмҲң, к°ҷмңјл©ҙ мӢңк°„ мҳӨлҰ„м°ЁмҲң)
    const ranking = await SpeedVocabKing.find({ eventName })
      .sort({ correctCount: -1, totalTime: 1 })
      .limit(100)
      .lean();

    res.json({ ok: true, ranking });
  } catch (err) {
    console.error('мҠӨн”јл“ң м–ҙнңҳмҷ• мҲңмң„ мЎ°нҡҢ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// ===== мӣ”к°„ мҠӨн”јл“ң лҸ…м„ңмҷ• API =====

// мӨ‘ліө м°ёк°Җ мІҙнҒ¬ API (к°ҷмқҖ мқҙлІӨнҠё + к°ҷмқҖ лҸ„м„ң + к°ҷмқҖ мӮ¬лһҢ = мӨ‘ліө м°ёк°Җ л¶Ҳк°Җ)
app.get('/api/speed-reading-king/check-event', async (req, res) => {
  try {
    const { eventName, bookId, grade, name, phone } = req.query;

    if (!eventName || !bookId || !grade || !name || !phone) {
      return res.status(400).json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    // к°ҷмқҖ мқҙлІӨнҠёлӘ… + к°ҷмқҖ лҸ„м„ң + к°ҷмқҖ мӮ¬лһҢмңјлЎң мқҙлҜё м°ёк°Җн–ҲлҠ”м§Җ нҷ•мқё
    const existing = await SpeedReadingKing.findOne({
      eventName,
      bookId,
      grade,
      name,
      phone
    }).lean();

    res.json({
      ok: true,
      exists: !!existing,
      message: existing ? 'мқҙлҜё н•ҙлӢ№ мқҙлІӨнҠём—җм„ң мқҙ лҸ„м„ңлЎң м°ёк°Җн•ҳм…ЁмҠөлӢҲлӢӨ.' : ''
    });
  } catch (err) {
    console.error('мҠӨн”јл“ң лҸ…м„ңмҷ• мӨ‘ліө мІҙнҒ¬ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// кІ°кіј м ҖмһҘ API
app.post('/api/speed-reading-king/save', async (req, res) => {
  try {
    const { eventName, bookId, bookTitle, grade, name, phone, correctCount, totalTime, totalQuestions } = req.body;

    if (!eventName || !bookId || !grade || !name || !phone) {
      return res.status(400).json({ ok: false, message: 'н•„мҲҳ м •ліҙк°Җ лҲ„лқҪлҗҳм—ҲмҠөлӢҲлӢӨ.' });
    }

    const result = new SpeedReadingKing({
      eventName,
      bookId,
      bookTitle: bookTitle || bookId,
      grade,
      name,
      phone,
      correctCount: correctCount || 0,
      totalTime: totalTime || 0,
      totalQuestions: totalQuestions || 10
    });

    await result.save();

    res.json({ ok: true, message: 'кІ°кіјк°Җ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ.' });
  } catch (err) {
    console.error('мҠӨн”јл“ң лҸ…м„ңмҷ• кІ°кіј м ҖмһҘ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

// мҲңмң„ мЎ°нҡҢ API (мӢңк°„ мҳӨлҰ„м°ЁмҲң - л№ лҘё мӢңк°„мқҙ лҶ’мқҖ мҲңмң„)
app.get('/api/speed-reading-king/ranking', async (req, res) => {
  try {
    const { eventName } = req.query;

    if (!eventName) {
      return res.status(400).json({ ok: false, message: 'мқҙлІӨнҠёлӘ…мқҙ н•„мҡ”н•©лӢҲлӢӨ.' });
    }

    // мқҙлІӨнҠёлі„ мҲңмң„ мЎ°нҡҢ (мӢңк°„ мҳӨлҰ„м°ЁмҲң - л№ лҘјмҲҳлЎқ лҶ’мқҖ мҲңмң„)
    const ranking = await SpeedReadingKing.find({ eventName })
      .sort({ totalTime: 1 })
      .limit(100)
      .lean();

    res.json({ ok: true, ranking });
  } catch (err) {
    console.error('мҠӨн”јл“ң лҸ…м„ңмҷ• мҲңмң„ мЎ°нҡҢ мҳӨлҘҳ:', err);
    res.status(500).json({ ok: false, message: 'м„ңлІ„ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.' });
  }
});

