// ===== м „нҷ”лІҲнҳё н•ҳмқҙн”Ҳ м ңкұ° мҲҳм • API (мһ„мӢң) =====
app.post("/api/fix-phone-hyphen", async (req, res) => {
  const { key, phone } = req.body;
  if (key !== ADMIN_KEY) {
    return res.status(403).json({ ok: false, message: "мқёмҰқ мӢӨнҢЁ" });
  }
  try {
    const user = await User.findOne({ phone: phone });
    if (!user) {
      return res.status(404).json({ ok: false, message: "мӮ¬мҡ©мһҗлҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ." });
    }
    const cleanPhone = phone.replace(/\D/g, "");
    user.phone = cleanPhone;
    user.id = cleanPhone;
    user.pw = cleanPhone;
    await user.save();
    console.log(`вң… м „нҷ”лІҲнҳё мҲҳм • мҷ„лЈҢ: ${phone} вҶ’ ${cleanPhone}`);
    res.json({ ok: true, message: `мҲҳм • мҷ„лЈҢ: ${phone} вҶ’ ${cleanPhone}`, user: { name: user.name, phone: user.phone } });
  } catch (err) {
    console.error("вқҢ м „нҷ”лІҲнҳё мҲҳм • мҳӨлҘҳ:", err);
    res.status(500).json({ ok: false, message: "мҲҳм • мӨ‘ мҳӨлҘҳ" });
  }
});

